 p_id=>wwv_flow_imp.id(215565984188408515)
,p_name=>'PO (Product Owner), Developer'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attribute_01=>'RETURN UPPER(:APP_USER) IN (''SCHFLO'', ''WISAND'');'
,p_version_scn=>1
,p_caching=>'BY_USER_BY_SESSION'
,p_comments=>unistr('2023-06-06 auf Wunsch hinzugef\00FCgt, damit Florian Schn\00F6nemeyer der Einzige ist, der die Buttons auf der Seite "Einstellungen" bet\00E4tigen kann, insbesondere zum Aussetzen der Synchronisierung')
);
end;
