prompt --application/shared_components/security/authorizations/app_readonly
begin
wwv_flow_imp_shared.create_security_scheme(
 p_id=>wwv_flow_imp.id(235084824408102045)
,p_name=>'* App - ReadOnly'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  berechtigt BOOLEAN;',
'BEGIN',
'  berechtigt := PCK_GLASCONTAINER.fb_hat_rolle(',
'    piv_username     => :APP_USER',
'   ,piv_rolle        => PCK_GLASCONTAINER.C_ROLLE_READONLY',
