prompt --application/shared_components/user_interface/lovs/wohndauer_ohne_no_resident
begin
wwv_flow_imp_shared.create_list_of_values(
 p_id=>wwv_flow_imp.id(232472978582298337)
,p_lov_name=>'WOHNDAUER (OHNE NO_RESIDENT)'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT CASE r',
'         WHEN ''RESIDENT_LESS_THAN_SIX_MONTHS'' THEN ''nein''',
'         WHEN ''RESIDENT_SIX_OR_MORE_MONTHS''   THEN ''ja''',
'       END AS D',
'     , r',
'  FROM TABLE(PCK_GLASCONTAINER.LOV(''residentStatus''))',
' WHERE r <> ''NO_RESIDENT''',
' ORDER BY',
'       CASE r',
'         WHEN ''RESIDENT_SIX_OR_MORE_MONTHS'' THEN 1     ',
'         WHEN ''RESIDENT_LESS_THAN_SIX_MONTHS''   THEN 2',
'       END'))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_use_local_sync_table=>false
,p_return_column_name=>'R'
,p_display_column_name=>'D'
,p_group_sort_direction=>'ASC'
,p_default_sort_direction=>'ASC'
,p_version_scn=>1
);
end;
