 p_id=>wwv_flow_imp.id(42985356186126770)
,p_build_option_name=>'@deprecated - enfernt'
,p_build_option_status=>'EXCLUDE'
,p_version_scn=>4107931890477
,p_default_on_export=>'EXCLUDE'
,p_build_option_comment=>unistr('Alle Items, die nicht mehr existieren sollen und nur noch \00FCbergangsweise zu Dokumentationszwecken in der App bleiben.')
);
wwv_flow_imp_shared.create_build_option(
 p_id=>wwv_flow_imp.id(56473619035308559)
,p_build_option_name=>'unsichtbar'
,p_build_option_status=>'EXCLUDE'
,p_version_scn=>4063064354025
,p_default_on_export=>'EXCLUDE'
,p_build_option_comment=>unistr('Alle Objekte, die vor\00FCbergehend oder endg\00FCltig nicht in Masken oder Reports dargestellt werden sollen, denen nichtsdestotrotz ein Wert zugewiesen werden kann, da sie eine Rolle in Prozessen spielen. Hintergrund ist, dass so "mal eben" das Item wieder')
||unistr(' angezeigt werden kann, mit korrekter Formatierung, und dabei nicht - wenn es ein Hidden Item w\00E4re - die Beschriftung "New" erh\00E4lt-')
);
wwv_flow_imp_shared.create_build_option(
 p_id=>wwv_flow_imp.id(59477255672398458)
,p_build_option_name=>'Tracking'
,p_build_option_status=>'INCLUDE'
,p_version_scn=>4066362249330
,p_build_option_comment=>unistr('@ticket FTTH-4003: Steuert, ob Prozesse namens "Track Page" bzw. "Track extra" ausgef\00FChrt werden. Gegebenfalls ist das Logging in der Entwicklung weitgehend \00FCberfl\00FCssig, sollte jedoch von Zeit zu Zeit testweise mitlaufen, um die Funktionalit\00E4t sicher')
||'zustellen.'
);
wwv_flow_imp_shared.create_build_option(
 p_id=>wwv_flow_imp.id(77783060430334499)
,p_build_option_name=>'@ticket FTTH-4456'
,p_build_option_status=>'INCLUDE'
,p_version_scn=>4101331427194
,p_build_option_comment=>'Hinweis bei Siebel-Ready in der Bestellerfassung sowie Darstellung von Adressen, die KEINEM Vermarktungscluster zugeordnet sind'
);
wwv_flow_imp_shared.create_build_option(
 p_id=>wwv_flow_imp.id(177183550576594203)
,p_build_option_name=>'@deprecated - markiert'
,p_build_option_status=>'INCLUDE'
,p_version_scn=>4107931909940
,p_default_on_export=>'INCLUDE'
,p_build_option_comment=>unistr('Muss immer auf "Include" stehen: Markiert alle Objekte, die als deprecated eingestuft sind und demn\00E4chst entfernt werden sollten. Dies kann beispielsweise ein Branch sein, der inzwischen obsolet ist, man sich aber nicht so recht traut ihn sofort zu l')
||unistr('\00F6schen.')
);
wwv_flow_imp_shared.create_build_option(
 p_id=>wwv_flow_imp.id(202886674411582214)
,p_build_option_name=>'DA: IG Copy Hack'
,p_build_option_status=>'INCLUDE'
,p_version_scn=>4047705787712
,p_build_option_comment=>unistr('Erm\00F6glicht es in einem Interactive Grid, den gesamten Textinhalt einer markierten Zelle mit [Strg][C] in die Zwischenablage zu kopieren, ohne den umst\00E4ndlichen Weg mit F8 nehmen zu m\00FCssen, den sich eh niemand merken kann')
);
