'@url https://www.oneoracledeveloper.com/2022/03/copy-cell-value-from-ig-global-edition.html',
'',
'function initIgCopyHack() {',
'document.addEventListener(''copy'', (event) => {',
'    event.clipboardData.setData(''text/plain'', $(document.activeElement)[0].innerText || window.getSelection());',
'    event.preventDefault();',
'});',
'}'))
,p_shortcut=>'function initIgCopyHack(){document.addEventListener("copy",e=>{e.clipboardData.setData("text/plain",$(document.activeElement)[0].innerText||window.getSelection()),e.preventDefault()})}'
);
end;
