prompt --application/shared_components/user_interface/shortcuts/fn_format_iban
begin
wwv_flow_imp_shared.create_shortcut(
 p_id=>wwv_flow_imp.id(226065854122759769)
,p_shortcut_name=>'FN_FORMAT_IBAN'
,p_shortcut_type=>'HTML_TEXT'
,p_version_scn=>1
,p_comments=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/**',
unistr(' * F\00FCgt allen Elementen im Argument "el" je einen Event-Handler hinzu,'),
unistr(' * der bei der Eingabe die IBAN in Viererbl\00F6cke formatiert'),
' * ',
' * @param el Collection von DOM-Elementen',
' */',
'function formatIBAN(el){',
'    for (let n = 0; n < el.length; n++) {',
'    el[n].addEventListener(''input'', (event) => {',
'        let v = event.target.value.toUpperCase().replace(/ /g, '''');',
'        let r = '''';',
'        for (let i = 0; i < v.length; i ++) {',
'            r += v[i];',
'            if ((i + 1) % 4 === 0 && i > 0) r += '' '';',
'        }',
'        event.target.value = r.trim();',
'        })',
'    }',
'}'))
,p_shortcut=>'function formatIBAN(t){for(let e=0;e<t.length;e++)t[e].addEventListener("input",e=>{var t=e.target.value.toUpperCase().replace(/ /g,"");let r="";for(let e=0;e<t.length;e++)r+=t[e],(e+1)%4==0&&0<e&&(r+=" ");e.target.value=r.trim()})}'
);
end;
/
