prompt --application/shared_components/user_interface/shortcuts/fn_copy_html_to_clipboard
begin
wwv_flow_imp_shared.create_shortcut(
 p_id=>wwv_flow_imp.id(233427742243875008)
,p_shortcut_name=>'FN_COPY_HTML_TO_CLIPBOARD'
,p_shortcut_type=>'HTML_TEXT'
,p_version_scn=>1
,p_comments=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/**',
' * Kopiert Rich Text / HTML in die Zwischenablage, wobei alle "<span>...</span>"-Abschnitte ',
' * durch ihren Inhalt ersetzt und HTML-Entities entfernt werden. ',
' * Die Funktion erwartet den formatierten Text als Parameter (kein Item oder jQuery-Objekt!). ',
' * Falls immer noch HTML-Tags enthalten sind, werden diese mit ausgegeben.',
' * ',
' * Beispiel-Aufruf in einer Dynamic Action:',
' * ',
' *   copyHtmlToClipboard($(this.triggeringElement).html());',
' */',
'',
'function copyHtmlToClipboard(html) {',
'',
'  function decodeEntities(encodedString) {',
'    var textArea = document.createElement(''textarea'');',
'    textArea.innerHTML = encodedString;',
'    return textArea.value;',
'  }',
'  function listener(e) {',
'    e.clipboardData.setData(''text/html'', html);',
'    e.clipboardData.setData(''text/plain'', html);',
'    e.preventDefault();',
'  }',
'',
'  var $html=$(''<div>'' + html + ''</div>'');',
'  $html.find(''section'').each(function(){$(this).replaceWith("\n"+$(this).html()+"\n");});',
'  $html.find(''span'').each(function(){$(this).replaceWith($(this).html());});',
'  html = decodeEntities($html.html());',
'',
'  document.addEventListener(''copy'', listener);',
'  document.execCommand(''copy'');',
'  document.removeEventListener(''copy'', listener);',
'}',
''))
,p_shortcut=>'function copyHtmlToClipboard(e){function t(t){t.clipboardData.setData("text/html",e),t.clipboardData.setData("text/plain",e),t.preventDefault()}var n,a,i=$("<div>"+e+"</div>");i.find("section").each(function(){$(this).replaceWith("\n"+$(this).html()+'
||'"\n")}),i.find("span").each(function(){$(this).replaceWith($(this).html())}),n=i.html(),(a=document.createElement("textarea")).innerHTML=n,e=a.value,document.addEventListener("copy",t),document.execCommand("copy"),document.removeEventListener("copy",'
||'t)}'
);
end;
/
