prompt --application/shared_components/user_interface/shortcuts/fn_diff_grid
begin
wwv_flow_imp_shared.create_shortcut(
 p_id=>wwv_flow_imp.id(246600483802918559)
,p_shortcut_name=>'FN_DIFF_GRID'
,p_shortcut_type=>'HTML_TEXT'
,p_version_scn=>1
,p_comments=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/**',
' * P20 (Auftragshistorie): Markiert die Zellen, die sich zwischen zwei aufeinanderfolgenen ',
' * Zeilen unterscheiden (siehe function diffAuftragshistorie)',
' */',
'function diffGrid(staticId, markerClass, columnList) {',
'    const IG = getInteractiveGridModel(staticId);',
'    if(!IG) return;',
'    const columns = columnList.split('','');',
'',
'    for(var i = 0; i < columns.length; i++) {',
'      findDifferences(columns[i].trim());',
'    }',
'',
'    function findDifferences(columnAlias) {',
'        if(!columnAlias) return; ',
'        var previousValue = "";',
'        var rowNumber = 0;',
'        IG.forEach(function(record) {',
'            rowNumber++;',
'            var columnValue = IG.getValue(record, columnAlias);  ',
'            if(rowNumber == 1) previousValue = columnValue;',
'            else {',
'                if(previousValue != columnValue) {',
'                    const upperRowSelector = ''#'' + staticId + '' tr:nth-child('' + (rowNumber - 1) + '')'' + '' span.'' + columnAlias;',
'                    $(upperRowSelector).closest(''td'').addClass(markerClass);',
'                    previousValue = columnValue;               ',
'                }',
'            }           ',
'        });       ',
'    }    ',
'}'))
,p_shortcut=>'function diffGrid(o,r,t){const a=getInteractiveGridModel(o);if(a){const i=t.split(",");for(var n=0;n<i.length;n++)!function(n){var i,c;n&&(i="",c=0,a.forEach(function(t){c++;t=a.getValue(t,n);1==c?i=t:i!=t&&($("#"+o+" tr:nth-child("+(c-1)+") span."+n'
||').closest("td").addClass(r),i=t)}))}(i[n].trim())}}'
);
end;
/
prompt --application/shared_components/user_interface/shortcuts/fn_copy_element_to_clipboard
begin
wwv_flow_imp_shared.create_shortcut(
 p_id=>wwv_flow_imp.id(329404003636509296)
,p_shortcut_name=>'FN_COPY_ELEMENT_TO_CLIPBOARD'
,p_shortcut_type=>'HTML_TEXT'
,p_version_scn=>1
,p_comments=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/**',
unistr('* Erm\00F6glicht das Kopieren des Textes eines Items in die Zwischenablage. Die Funktion erwartet ein'),
unistr('* beliebiges Element (Selektor, DOM-Element, jQuery-Objekt, ...), dessen Text vollst\00E4ndig'),
'* ausgelesen wird.',
'*/',
'function copyElementToClipboard(elem) {',
'',
'  var $elem= $(elem);',
'  var text= $elem.html();',
'',
'  function listener(e) {',
'    e.clipboardData.setData("text/html", text);',
'    e.clipboardData.setData("text/plain", text);',
'    e.preventDefault();',
'  }',
'  document.addEventListener("copy", listener);',
'  document.execCommand("copy");',
'  document.removeEventListener("copy", listener);',
'}',
''))
,p_shortcut=>'function copyElementToClipboard(t){var e=$(t).html();function a(t){t.clipboardData.setData("text/html",e),t.clipboardData.setData("text/plain",e),t.preventDefault()}document.addEventListener("copy",a),document.execCommand("copy"),document.removeEvent'
||'Listener("copy",a)}'
);
end;
/
prompt --application/shared_components/user_interface/shortcuts/fn_get_interactive_grid_model
begin
wwv_flow_imp_shared.create_shortcut(
 p_id=>wwv_flow_imp.id(358040518981854329)
,p_shortcut_name=>'FN_GET_INTERACTIVE_GRID_MODEL'
,p_shortcut_type=>'HTML_TEXT'
,p_reference_id=>153807022351726899
,p_comments=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('Function zum Einsatz in diversen Seiten, wo man sich mit JavaScript auf ein Interaktives Grid beziehen m\00F6chte. Man \00FCbergibt die Static ID des Grids (wie im Page Designer bei der Region deklariert) und erh\00E4lt entweder das grid.model-Objekt zur\00FCck oder')
||unistr(' undefined. Vorteil: Code-Kapselung (die IG-Methoden \00E4ndern sich oft!). Die Funktion pr\00FCft nach jeder Zuweisung, ob diese erfolgreich war, so dass niemals Methoden eines nicht existierenden Objekts aufgerufen werden, was Laufzeitfehler verursachen w\00FC')
||unistr('rde. Beispiel: Man \00E4ndert die statische ID des Grids und ermittelt das model auf herk\00F6mmliche Art, dann schl\00E4gt ggf. das gesamte JavaScript der Seite fehl!'),
'',
'@author  Andreas Wismann  <wismann@when-others.com>',
'',
'@usage korrekt:',
'  var model = getInteractiveGridModel(''meineStatischeID'');',
unistr('  // diese Pr\00FCfung muss erfolgen:'),
'  if(!!model) { /* weitermachen */ }',
'',
unistr('@usage anstatt wie im Internet h\00E4ufig zu finden ist:'),
'  var model = apex.region("existiertNicht").widget().interactiveGrid("getViews", "grid").model();',
unistr('  // dies ergibt einen Laufzeitfehler, noch bevor man den R\00FCckgabewert \00FCberhaupt pr\00FCfen kann')))
,p_shortcut=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function getInteractiveGridModel(staticId) {',
'  var region = apex.region(staticId);',
'      if(!region) return;',
'  var widget = region.widget();',
'      if(!region) return;',
'  var grid = widget.interactiveGrid(''getViews'',''grid'');',
'      if(!grid) return;',
'  return grid.model;',
'}'))
);
end;
/
