,p_plug_display_sequence=>20
,p_include_in_reg_disp_sel_yn=>'Y'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select POB.ID,',
'       POB.ID AS UUID,',
'       TEMPLATEID,',
'       AKTION."NAME" AS AKTION,',
'       PRODUKT."NAME" AS PRODUKT,',
'       DEVICECATEGORY,',
'       DEVICEOWNERSHIP,',
'       INSTALLATIONSERVICE,',
'       HOUSECONNECTIONPRICE,',
'       SUMM_ORDERSUMMARYFILEID,',
'       STATE,',
'       STATE AS STATUS,',
'       VKZ,',
'       CLIENT,',
'       CUSTOMERNUMBER,',
'       -- @ticket FTTH-4470:',
'       CASE WHEN ACCOUNT_ID IS NULL THEN CUSTOMERNUMBER  ',
unistr('            ELSE ''<a href="#" data-account_id="'' || ACCOUNT_ID || ''" title="Siebel-Kundenmaske \00F6ffnen">'' || CUSTOMERNUMBER || ''</a>'''),
'       END AS KUNDENNUMMER,',
'       CUSTOMER_BUSINESSNAME,',
'       CUSTOMER_SALUTATION,',
'       CUSTOMER_TITLE,',
'       CUSTOMER_NAME_FIRST,',
'       CUSTOMER_NAME_LAST,',
'       CUSTOMER_BIRTHDATE,',
'       CUSTOMER_EMAIL,',
'       CUSTOMER_PHONE_COUNTRYCODE,',
'       CUSTOMER_PHONE_AREACODE,',
'       CUSTOMER_PHONE_NUMBER,',
'       HOUSESERIALNUMBER,',
'       CUSTOMER_RESIDENTSTATUS,',
'       INSTALL_ADDR_COUNTRY,',
'       INSTALL_ADDR_ZIPCODE,',
'       INSTALL_ADDR_CITY,',
'       INSTALL_ADDR_STREET,',
'       INSTALL_ADDR_HOUSENUMBER,',
'       INSTALL_ADDR_ADDITION,',
'       -- @ticket FTTH-4625:',
'       A.STR,',
'       A.HNR_KOMPL,',
'       A.GEBAEUDETEIL_NAME,',
'       A.PLZ,',
'       A.ORT_KOMPL,',
'       PROVIDERCHG_CURRENT_PROVIDER,',
'       PROVIDERCHG_KEEP_PHONE_NUMBER,',
'       PROVIDERCHG_PHONE_COUNTRYCODE,',
'       PROVIDERCHG_PHONE_AREACODE,',
'       PROVIDERCHG_PHONE_NUMBER,',
'       PROVIDERCHG_CONTRACT_CANCELLED,',
'       PROVIDERCHG_CANCELLATION_DATE,',
'       PROVIDERCHG_OWNER_SALUTATION,',
'       PROVIDERCHG_OWNER_NAME_FIRST,',
'       PROVIDERCHG_OWNER_NAME_LAST,',
'       ACCOUNT_SEPAMANDATE,',
'       ACCOUNT_HOLDER,',
'       LANDLORD_NAME_LAST,',
'       ACCOUNT_IBAN,',
'       LANDLORD_NAME_FIRST,',
'       LANDLORD_EMAIL,',
'       LANDLORD_TITLE,',
'       LANDLORD_ADDR_CITY,',
'       LANDLORD_ADDR_STREET,',
'       LANDLORD_ADDR_COUNTRY,',
'       LANDLORD_ADDR_ZIPCODE,',
'       LANDLORD_ADDR_HOUSENUMBER,',
'       LANDLORD_ADDR_ADDITION,',
'       LANDLORD_LEGALFORM,',
'       LANDLORD_SALUTATION,',
'       LANDLORD_PHONE_NUMBER,',
'       LANDLORD_PHONE_AREACODE,',
'       LANDLORD_PHONE_COUNTRYCODE,',
'       LANDLORD_BUSINESSORNAME,',
'       PROP_RESIDENTIAL_UNIT,',
'       PROP_OWNER_ROLE,',
'       LANDLORD_AGREED,',
'       SUMM_PRECONTRACTINFORMATION,',
'       SUMM_GENERALTERMSANDCONDITIONS,',
'       SUMM_WAIVERIGHTOFREVOCATION,',
'       SUMM_EMAILMARKETING,',
'       SUMM_PHONEMARKETING,',
'       SUMM_SMSMMSMARKETING,',
'       SUMM_MAILMARKETING,',
'       CUSTOMER_PREV_ADDR_STREET,',
'       CUSTOMER_PREV_ADDR_HOUSENUMBER,',
'       CUSTOMER_PREV_ADDR_ADDITION,',
'       CUSTOMER_PREV_ADDR_ZIPCODE,',
'       CUSTOMER_PREV_ADDR_CITY,',
'       CUSTOMER_PREV_ADDR_COUNTRY,',
'       CUSTOMER_UPD_EMAIL,',
'       CUSTOMER_UPD_PHONE_COUNTRYCODE,',
'       CUSTOMER_UPD_PHONE_AREACODE,',
'       CUSTOMER_UPD_PHONE_NUMBER,',
'       APEX$SYNC_STEP_STATIC_ID,',
'       APEX$ROW_SYNC_TIMESTAMP,',
'       CASE WHEN PROVIDERCHG_CURRENT_PROVIDER IS NULL THEN 0 ELSE 1 END AS ANBIETERWECHSEL,',
'     --CASE WHEN PROP_OWNER_ROLE = ''OWNER'' AND PROP_RESIDENTIAL_UNIT = ''ONE'' THEN 1 ELSE 0 END AS GEE_ERTEILT, -- 2022-06-15 (Johannes Reinig)',
'       CASE WHEN PROP_OWNER_ROLE = ''OWNER'' AND PROP_RESIDENTIAL_UNIT IN (''ONE'', ''MORE_THAN_ONE'') THEN 1 ELSE 0 END AS GEE_ERTEILT, -- 2022-09-13 @fschoenemeyer',
'     --CASE WHEN CUSTOMER_UPD_EMAIL IS NULL THEN ''N'' ELSE ''B'' END AS KUNDENSTATUS,',
'       CASE WHEN IS_NEW_CUSTOMER = ''true'' THEN ''N'' ELSE ''B'' END AS KUNDENSTATUS, -- Neukunde, Bestandskunde',
'       IS_NEW_CUSTOMER,',
'       CREATED,',
'       LAST_MODIFIED,',
'       VERSION,',
'       CHANGED_BY, -- neu 2023-06-20',
'       PROCESS_LOCK,',
'       PROCESS_LOCK AS PROCESS_LOCK_DISPLAY,',
'       PROCESS_LOCK_LAST_MODIFIED,',
'       CANCELLED_BY,',
'       CANCEL_REASON,',
'       CANCEL_DATE,',
unistr('    -- TO_DATE(POB.CANCEL_DATE) - TO_DATE(POB.CREATED) AS CANCEL_TIMESPAN, -- 2024-06-11 @bug m\00F6glicherweise die Ursache f\00FCr ORA-21700'),
'       SIEBEL_ORDER_NUMBER,',
'       SIEBEL_ORDER_ROWID,',
'       SIEBEL_READY,',
'       POB.WHOLEBUY_PARTNER,',
'       POB.MANUAL_TRANSFER,',
'       service_plus_email,',
'       vc.bezeichnung as vermarktungscluster,',
'       vc.status as vermarktungscluster_status,',
'       vc.ausbau_plan_termin,',
'       vc.mindestbandbreite as bandbreite_min,',
'       vc.zielbandbreite_geplant as bandbreite_max,',
'       POB.TECHNOLOGY as DIENSTTYP,',
'       POB.ONT_PROVIDER,',
'       -- 2024-08-21 @ticket FTTH-3727 @SYNC #20:',
'       POB.CONNECTIVITY_ID,',
'       POB.RT_CONTACT_DATA_TICKET_ID,',
'       POB.LANDLORD_INFORMATION_REQUIRED,',
'       UPDATE_CUSTOMER_IN_SIEBEL,',
'       HOME_ID,',
'       ACCOUNT_ID,',
'       POB.AVAILABILITY_DATE,',
'       REPLACE(A.AUSBAUGEBIETE       , ''|'', ''<br/>'') AS AUSBAUGEBIETE,',
'       REPLACE(A.AUSBAUGEBIETSTYPEN  , ''|'', ''<br/>'') AS AUSBAUGEBIETSTYPEN, ',
'       REPLACE(A.ERSCHLIESSUNGEN     , ''|'', ''<br/>'') AS ERSCHLIESSUNGEN,',
'       REPLACE(A.STATUS_AUSBAUGEBIET , ''|'', ''<br/>'') AS STATUS_AUSBAUGEBIET,',
'       REPLACE(A.PROJEKTE            , ''|'', ''<br/>'') AS PROJEKTE,',
'       REPLACE(A.PROJEKTNAMEN        , ''|'', ''<br/>'') AS PROJEKTNAMEN',
'  FROM FTTH_WS_SYNC_PREORDERS POB',
'  JOIN POB_ADRESSEN A ON (A.HAUS_LFD_NR = POB.HOUSESERIALNUMBER)',
'  JOIN FTTH_GLASCONTAINER_PRODUKTE PRODUKT ON (PRODUKT.TEMPLATE_ID = POB.TEMPLATEID)',
'  JOIN FTTH_GLASCONTAINER_AKTIONEN AKTION  ON (AKTION.CODE = PRODUKT.AKTION)',
'  LEFT JOIN VERMARKTUNGSCLUSTER_OBJEKT VCO ON (VCO.HAUS_LFD_NR = POB.HOUSESERIALNUMBER)',
'  LEFT JOIN VERMARKTUNGSCLUSTER VC         ON (VC.VC_LFD_NR = VCO.VC_LFD_NR)',
' WHERE :P10_SEARCHFLAG IS NOT NULL'))
,p_optimizer_hint=>'LEADING(FTTH_WS_SYNC_PREORDERS)'
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P10_SEARCHFLAG'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'MILLIMETERS'
