wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(81403255628397449)
,p_event_id=>wwv_flow_imp.id(81403014183397447)
,p_event_result=>'TRUE'
,p_action_sequence=>20
,p_execute_on_page_init=>'N'
,p_name=>'Kundennummer persistieren'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'let $link = $(this.triggeringElement);',
'let knr = $link.text();',
'if(!knr) apex.da.cancel(); // abbrechen, wenn es keine Kundennummer gibt',
'',
'let accountId = $link.data(''account_id'');',
'if(!accountId) apex.da.cancel(); // abbrechen, wenn es keine account_id gibt',
'',
'apex.item(''P10_TEMP_KNR'').setValue(knr);',
'apex.item(''P10_TEMP_ACCOUNT_ID'').setValue(accountId);',
''))
,p_da_action_comment=>unistr('@ticket FTTH-4470: Zur Ermittlung des Links im n\00E4chsten Schritt werden die Werte der Kundennummer und der Account-ID in Hidden Items geschrieben.')
);
wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(81403380205397450)
,p_event_id=>wwv_flow_imp.id(81403014183397447)
,p_event_result=>'TRUE'
,p_action_sequence=>30
,p_execute_on_page_init=>'N'
,p_name=>'AccountId ermitteln'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P10_TEMP_HREF := PCK_GLASCONTAINER.fv_href_siebel_kundenmaske(',
'    piv_account_id    => :P10_TEMP_ACCOUNT_ID',
'  , piv_kundennummer  => :P10_TEMP_KNR',
');'))
,p_attribute_02=>'P10_TEMP_KNR, P10_TEMP_ACCOUNT_ID'
,p_attribute_03=>'P10_TEMP_HREF'
,p_attribute_04=>'N'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
,p_da_action_comment=>unistr('@ticket FTTH-4470: Der Link zur Siebel-Kundenmaskte wird in dieser Action serverseitig generiert, da er umgebungsabh\00E4ngig ist. Es w\00E4re f\00FCr die Report-Performance sch\00E4dlich, im Voraus f\00FCr jeden Auftrag diese zus\00E4tzliche Berechnung durchzuf\00FChren.')
);
wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(81403682144397453)
,p_event_id=>wwv_flow_imp.id(81403014183397447)
,p_event_result=>'TRUE'
,p_action_sequence=>40
,p_execute_on_page_init=>'N'
,p_name=>unistr('Siebel in neuem Tab \00F6ffnen')
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'let href = apex.item(''P10_TEMP_HREF'').getValue();',
'let knr = apex.item(''P10_TEMP_KNR'').getValue();',
'let accountId = apex.item(''P10_TEMP_ACCOUNT_ID'').getValue();',
'if(!!href) {',
'    window.open(href, ''_blank'').focus();',
'} else {',
