wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(61956175630854131)
,p_plug_name=>unistr('Vermarktungsf\00E4hige Adressen:')
,p_region_template_options=>'#DEFAULT#:t-Region--noBorder:t-Region--scrollBody:margin-top-lg'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>50
,p_query_type=>'FUNC_BODY_RETURNING_SQL'
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  cl_sql CLOB := q''[',
'SELECT a.haus_lfd_nr haus_lfd_nr_return',
'     , a.haus_lfd_nr haus_lfd_nr_display',
'     , a.plz',
'     , a.ort_kompl AS ORT',
'     , a.str',
'     , a.hnr_kompl AS HNR',
'     , a.gebaeudeteil_name AS GEBAEUDETEIL     ',
'     , vc.vc_lfd_nr',
'     , vc.status',
'     , vc.bezeichnung as vermarktungscluster',
'     , vc.mindestbandbreite',
'     , vc.zielbandbreite_geplant',
'     , vc.wholebuy',
'  FROM v_adressen a',
'  JOIN vermarktungscluster_objekt vco on (a.haus_lfd_nr = vco.haus_lfd_nr)',
'  JOIN vermarktungscluster vc ON (vc.vc_lfd_nr = vco.vc_lfd_nr)',
' WHERE vc.status in (''PREMARKETING'', ''UNDERCONSTRUCTION'')',
'        AND vc.dnsttp_lfd_nr IN (',
'             51 -- FTTB',
'            ,70 -- FTTH',
'            ,71 -- G.fast',
'            ,89 -- FTTH BSA L2',
'            ,90 -- FTTH BSA L2 DG',
'       )',
' ]'';',
'',
'BEGIN',
'',
'  RETURN cl_sql ',
'         || pck_strav_query.fcl_adress_where_query',
'            (',
'                 piv_search_all   => :P14_SEARCH_ALL',
'               , piv_do_search    => ''Y''',
'               , piv_alias        => ''a''',
'            )',
'  ;',
'END;',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P14_SEARCH_ALL'
,p_plug_display_condition_type=>'ITEM_IS_NOT_NULL'
,p_plug_display_when_condition=>'P14_SEARCH_ALL'
,p_required_patch=>-wwv_flow_imp.id(77783060430334499)
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('-- ///// demn\00E4chst, Stand 2024-07-02:'),
unistr(' WHERE vc.status in (''PREMARKETING'', ''UNDERCONSTRUCTION'') -- zuk\00FCnftig bei WHOLEBUY: HOMESREADY, HOMESCONNECTED mit FTTH-4009'),
unistr('   AND vc.WHOLEBUY IS NULL -- (entf\00E4llt  mit FTTH-3360)'),
'   AND vc.dnsttp_lfd_nr IN (',
'             51 -- FTTB (neu) -- kein ONT',
'            ,70 -- FTTH -- mit ONT-Attribut',
'            ,71 -- G.fast (neu) -- kein ONT',
unistr('          --,89 -- FTTH BSA L2 (demn\00E4chst mit FTTH-3360), kein ONT'),
unistr('          --,90 -- FTTH BSA L2 DG (demn\00E4chst mit FTTH-3360), kein ONT'),
'       )',
'       ',
unistr('@krakar @ticket Ftth-3360: Diensttypen FTTH BSA L2 und FTTH BSA L2 DG wurden hinzugef\00FCgt; Anpassung der Funktion von P14_SEARCH_ALL, sodass auch die Wholebuy-Partner angezeigt werden')))
);
