wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(77779336264327305)
,p_plug_name=>unistr('Vermarktungsf\00E4hige Adressen:')
,p_region_template_options=>'#DEFAULT#:t-Region--noBorder:t-Region--scrollBody:margin-top-lg'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>60
,p_query_type=>'FUNC_BODY_RETURNING_SQL'
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  cl_sql CLOB := q''[',
'SELECT a.haus_lfd_nr haus_lfd_nr_return',
'     , a.haus_lfd_nr haus_lfd_nr_display',
'     , a.plz',
'     , a.ort_kompl AS ORT',
'     , a.str',
'     , a.hnr_kompl AS HNR',
'     , a.gebaeudeteil_name AS GEBAEUDETEIL     ',
'     , vc.vc_lfd_nr',
'     , vc.status',
'     , vc.bezeichnung as vermarktungscluster',
'     , vc.mindestbandbreite',
'     , vc.zielbandbreite_geplant',
'     , vc.wholebuy',
'     , case when vc.status in (''PREMARKETING'', ''UNDERCONSTRUCTION'') then ''100'' else ''16'' end as jump_target',
'  FROM v_adressen a',
'  LEFT JOIN vermarktungscluster_objekt vco on (a.haus_lfd_nr = vco.haus_lfd_nr)',
'  LEFT JOIN vermarktungscluster vc ',
'    ON (vc.vc_lfd_nr = vco.vc_lfd_nr)',
' WHERE 1=1',
' ]''; -- SQL muss mit einer WHERE-Klausel enden!',
'',
'BEGIN',
'',
'  RETURN cl_sql ',
'         || pck_strav_query.fcl_adress_where_query',
'            (',
'                 piv_search_all   => :P14_SEARCH_ALL',
'               , piv_do_search    => ''Y''',
'               , piv_alias        => ''a''',
'            )',
'  ;',
'END;',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P14_SEARCH_ALL'
,p_plug_display_condition_type=>'ITEM_IS_NOT_NULL'
,p_plug_display_when_condition=>'P14_SEARCH_ALL'
,p_required_patch=>wwv_flow_imp.id(77783060430334499)
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'@ticket FTTH-4456',
unistr('Im Gegensatz zum fr\00FCher verwendeten Report spielt der Status des Vermarktungsclusters zun\00E4chst keine Rolle, sondern wird farblich markiert. Die Liste mit den geforderten Technologien entf\00E4llt ebenfalls, da (After Daily vom 2025-02-19) es \00FCberhaupt ke')
||unistr('ine anderen in einem Vermarktungscluster gibt. Wichtig f\00FCr das dynamische SQL: Es MUSS mit einer WHERE-Klausel enden (hier also: WHERE 1=1), da sonst die Funktion fcl_adress_where_query keine sinnvolle Erg\00E4nzung hinzuf\00FCgt!')))
);
