wwv_flow_imp_page.create_page_branch(
 p_id=>wwv_flow_imp.id(200420341235775229)
,p_branch_name=>'Aufruf aus SIEBEL: Weiter zur Erfassung'
,p_branch_action=>'f?p=&APP_ID.:100:&SESSION.:SIEBEL:&DEBUG.:100:P100_HAUS_LFD_NR,P100_MANDANT,P100_SIEBEL_KUNDENNUMMER,P100_KUNDENSTATUS:&P14_HAUS_LFD_NR.,&P14_MANDANT.,&P14_KUNDENNUMMER.,B&success_msg=#SUCCESS_MSG#'
,p_branch_point=>'BEFORE_HEADER'
,p_branch_type=>'REDIRECT_URL'
,p_branch_sequence=>10
,p_branch_condition_type=>'EXPRESSION'
,p_branch_condition=>wwv_flow_string.join(wwv_flow_t_varchar2(
'UPPER(:REQUEST) = ''SIEBEL'' AND',
'PCK_GLASCONTAINER_ORDER.SIEBEL_VORBESTELLUNG_BRANCH(',
'    piv_haus_lfd_nr      => :P14_HAUS_LFD_NR',
'   ,piv_kundennummer     => :P14_KUNDENNUMMER',
'   ,piv_mandant          => :P14_MANDANT',
'   ,pov_ausbaustatus     => :P14_AUSBAUSTATUS',
'   ,pov_wholebuy_partner => :P14_WHOLEBUY_PARTNER',
'   ,pov_technologie      => :P14_TECHNOLOGIE',
'   ,pov_usermessage      => :P14_USERMESSAGE',
'   ,pov_link_objektinfo  => :P14_LINK',
')'))
,p_branch_condition_text=>'PLSQL'
,p_security_scheme=>wwv_flow_imp.id(238128121341675592)
,p_branch_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'@ticket FTTH-4084. Der Aufruf der Funktion SIEBEL_VORBESTELLUNG_BRANCH hat einen doppelten Zweck:',
'1. Falls ein passender Status ermittelt wird, springt der Glascontainer zur Auftragserfassung. ',
'2. Zugleich werden die Werte der OUT-Parameter in den Hidden Items hinterlegt. Seite 100 holt sich diese dann ab. ',
'',
'Der Link aus SIEBEL hat folgendes Format:',
'https://romae.netcologne.intern/ords_e/r/roma/glascontainer/vorbestellung?request=siebel&p14_haus_lfd_nr=1219352&p14_kundennummer=13003020&p14_mandant=nc'))
);
