 p_id=>wwv_flow_imp.id(225272368173440325)
,p_plug_name=>'OFFLINE-Modus'
,p_region_css_classes=>'problem'
,p_icon_css_classes=>'fa-cloud-ban'
,p_region_template_options=>'#DEFAULT#:margin-top-none:margin-bottom-none:margin-left-none:margin-right-none'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2674017834225413037
,p_plug_display_sequence=>50
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_last_sync DATE;',
'  v_link_einstellungen VARCHAR2(1000);',
'BEGIN',
'  :P20_WS_ERRORCODE := PCK_GLASCONTAINER.C_OFFLINEMODUS; -- der Benutzer kann hierdurch nichts abspeichern',
'  :P20_WS_ERRORMESSAGE := PCK_GLASCONTAINER.C_WS_MODUS_OFFLINE;',
'  v_last_sync := PCK_GLASCONTAINER.fd_ws_last_sync_date(piv_uuid => :P20_UUID);',
'  v_link_einstellungen :=',
'        APEX_PAGE.GET_URL(',
'            p_application => :APP_ID',
'           ,p_page        => 10100',
'           ,p_session     => :APP_SESSION',
'           ,p_items       => NULL',
'           ,p_values      => NULL',
'           );',
'  htp.p(',
unistr('''Sie haben sich f\00FCr den Offline-Datenabruf entschieden (<a href="'' || v_link_einstellungen '),
'|| ''">Einstellungen &gt; Abruf von Auftragsdaten</a>). Sie sehen die Daten aus der letzten Synchronisierung ''',
'|| CASE WHEN trunc(v_last_sync) = TRUNC(SYSDATE)',
'   THEN',
'     ''von heute, '' || TO_CHAR(v_last_sync, ''HH24:MI'') || '' Uhr''',
'   WHEN v_last_sync IS NULL THEN ''''',
'   ELSE',
'     ''vom '' || TO_CHAR(v_last_sync, ''DD.MM.YYYY'') || '' um ''',
'            || TO_CHAR(v_last_sync, ''HH24:MI'') || '' Uhr''',
'   END',
'|| '' &mdash; die Bearbeitung ist deaktiviert.</strong>''',
');',
'END;'))
,p_plug_source_type=>'NATIVE_PLSQL'
,p_plug_display_condition_type=>'EXPRESSION'
,p_plug_display_when_condition=>':P20_UUID IS NOT NULL AND :P10100_WS_MODUS = PCK_GLASCONTAINER.C_WS_MODUS_OFFLINE'
,p_plug_display_when_cond2=>'PLSQL'
,p_plug_comment=>unistr('Hinweistext an den Benutzer, dass sich die Seite im OFFLINE-Modus befindet und er dadurch nichts am Auftrag \00E4ndern kann.')
);
