wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(228641804980370297)
,p_plug_name=>'Problem beim Abrufen der Daten'
,p_region_css_classes=>'problem'
,p_icon_css_classes=>'fa-warning'
,p_region_template_options=>'#DEFAULT#:margin-top-none:margin-bottom-none:margin-left-none:margin-right-none'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2674017834225413037
,p_plug_display_sequence=>40
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_last_sync DATE;',
'BEGIN',
'  v_last_sync := PCK_GLASCONTAINER.fd_ws_last_sync_date(piv_uuid => :P20_UUID);',
'  htp.p(',
'  CASE :P20_WS_ERRORCODE WHEN ''-20404'' THEN ''Der Auftrag kann momentan nicht abgerufen werden. Sie sehen die zuletzt synchronisierten Daten''',
'  ELSE ''Der Webservice, der die aktuellen Auftragsdaten liefert, ist nicht erreichbar (&P20_WS_ERRORMESSAGE.).''',
'        || ''<br/><strong>Stattdessen sehen Sie hier die Daten aus der letzten Synchronisierung '' ',
'        || CASE WHEN trunc(v_last_sync) = TRUNC(SYSDATE)',
'           THEN',
'             ''von heute, '' || TO_CHAR(v_last_sync, ''HH24:MI'') || '' Uhr''',
'           WHEN v_last_sync IS NULL THEN ''''',
'           ELSE',
'             ''vom '' || TO_CHAR(v_last_sync, ''DD.MM.YYYY'') || '' um ''',
'                    || TO_CHAR(v_last_sync, ''HH24:MI'') || '' Uhr''',
'           END',
'  END',
'',
'|| '' &mdash; die Bearbeitung ist deaktiviert.</strong>''',
');',
'END;'))
,p_plug_source_type=>'NATIVE_PLSQL'
,p_plug_display_condition_type=>'EXPRESSION'
,p_plug_display_when_condition=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P20_UUID IS NOT NULL AND ',
':P20_WS_ERRORCODE <> PCK_GLASCONTAINER.C_ORDER_IS_LOCKED AND',
':P10100_WS_MODUS <> PCK_GLASCONTAINER.C_WS_MODUS_OFFLINE'))
,p_plug_display_when_cond2=>'PLSQL'
,p_plug_comment=>'Region wird angezeigt, wenn es ein technisches Problem mit dem Webservice gibt, jedoch nicht bei SQLCODE C_ORDER_IS_LOCKED (-20003).'
);
