wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(364725142548875591)
,p_plug_name=>'IG Auftragshistorie'
,p_region_name=>'auftragshistorie'
,p_parent_plug_id=>wwv_flow_imp.id(335127932166263728)
,p_region_css_classes=>'scrollbar-on-top'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--noBorders:margin-top-md'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>40
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'with produkt_lov as (',
'    SELECT d, r FROM TABLE(PCK_GLASCONTAINER.LOV_PRODUKTE(',
'        piv_template_id     => :P20_PRODUKT,',
'        pin_min_bandbreite  => NULL,',
'        pin_max_bandbreite  => NULL',
'    ))',
'),',
'router_lov as (SELECT d, r FROM TABLE(PCK_GLASCONTAINER.LOV(''deviceCategory'', ''TCOM''))),',
'status_lov as (SELECT d, r FROM TABLE(PCK_GLASCONTAINER.LOV(''state''))),',
'router_eigentum_lov AS (SELECT d, r FROM TABLE(PCK_GLASCONTAINER.LOV(''ROUTER_EIGENTUM''))),',
'installationsservice_lov AS (',
'    -- //// @todo @Herbst-2023-Tarife',
unistr('    -- ///@\00E4ndern: 2022-11-02: NetStart Plus in der Produktion rausgeworfen, darum ist die Abfrage zur Zeit nicht serverbasiert:'),
'    SELECT ''ohne Service'' AS D, ''NONE'' AS R FROM DUAL UNION ALL',
'    SELECT ''NetStart'', ''NETSTART'' FROM DUAL',
')',
'select ID,',
'       TEMPLATEID,',
'       produkt_lov.d AS PRODUKT,',
'       DEVICECATEGORY,',
'       router_lov.d AS ROUTER_AUSWAHL,',
'       DEVICEOWNERSHIP,',
'       router_eigentum_lov.d AS ROUTER_EIGENTUM,',
'       INSTALLATIONSERVICE,',
'       installationsservice_lov.d AS EINRICHTUNGSSERVICE,',
'       HOUSECONNECTIONPRICE,',
'       SUMM_ORDERSUMMARYFILEID,',
'       STATE,',
'       status_lov.d AS STATUS,',
'       VKZ,',
'       CLIENT,',
'       CUSTOMERNUMBER,',
'       CUSTOMER_BUSINESSNAME,',
'       CUSTOMER_SALUTATION,',
'       CUSTOMER_TITLE,',
'       CUSTOMER_NAME_FIRST,',
'       CUSTOMER_NAME_LAST,',
'       CUSTOMER_BIRTHDATE,',
'       CUSTOMER_EMAIL,',
'       CUSTOMER_PHONE_COUNTRYCODE,',
'       CUSTOMER_PHONE_AREACODE,',
'       CUSTOMER_PHONE_NUMBER,',
'       HOUSESERIALNUMBER,',
'       CUSTOMER_RESIDENTSTATUS,',
'       INSTALL_ADDR_COUNTRY,',
'       INSTALL_ADDR_ZIPCODE,',
'       INSTALL_ADDR_CITY,',
'       INSTALL_ADDR_STREET,',
'       INSTALL_ADDR_HOUSENUMBER,',
'       INSTALL_ADDR_ADDITION,',
'       PROVIDERCHG_CURRENT_PROVIDER,',
'       PROVIDERCHG_KEEP_PHONE_NUMBER,',
'       PROVIDERCHG_PHONE_COUNTRYCODE,',
'       PROVIDERCHG_PHONE_AREACODE,',
'       PROVIDERCHG_PHONE_NUMBER,',
'       PROVIDERCHG_CONTRACT_CANCELLED,',
'       PROVIDERCHG_CANCELLATION_DATE,',
'       PROVIDERCHG_OWNER_SALUTATION,',
'       PROVIDERCHG_OWNER_NAME_FIRST,',
'       PROVIDERCHG_OWNER_NAME_LAST,',
'       ACCOUNT_SEPAMANDATE,',
'       ACCOUNT_HOLDER,',
'       LANDLORD_NAME_LAST,',
'       ACCOUNT_IBAN,',
'       LANDLORD_NAME_FIRST,',
'       LANDLORD_EMAIL,',
'       LANDLORD_TITLE,',
'       LANDLORD_ADDR_CITY,',
'       LANDLORD_ADDR_STREET,',
'       LANDLORD_ADDR_COUNTRY,',
'       LANDLORD_ADDR_ZIPCODE,',
'       LANDLORD_ADDR_HOUSENUMBER,',
'       LANDLORD_ADDR_ADDITION,',
'       LANDLORD_LEGALFORM,',
'       LANDLORD_SALUTATION,',
'       LANDLORD_PHONE_NUMBER,',
'       LANDLORD_PHONE_AREACODE,',
'       LANDLORD_PHONE_COUNTRYCODE,',
'       LANDLORD_BUSINESSORNAME,',
'       PROP_RESIDENTIAL_UNIT,',
'       PROP_OWNER_ROLE,',
'       LANDLORD_AGREED,',
'       SUMM_PRECONTRACTINFORMATION,',
'       SUMM_GENERALTERMSANDCONDITIONS,',
'       SUMM_WAIVERIGHTOFREVOCATION,',
'       SUMM_EMAILMARKETING,',
'       SUMM_PHONEMARKETING,',
'       SUMM_SMSMMSMARKETING,',
'       SUMM_MAILMARKETING,',
'       CUSTOMER_PREV_ADDR_STREET,',
'       CUSTOMER_PREV_ADDR_HOUSENUMBER,',
'       CUSTOMER_PREV_ADDR_ADDITION,',
'       CUSTOMER_PREV_ADDR_ZIPCODE,',
'       CUSTOMER_PREV_ADDR_CITY,',
'       CUSTOMER_PREV_ADDR_COUNTRY,',
'       CUSTOMER_UPD_EMAIL,',
'       CUSTOMER_UPD_PHONE_COUNTRYCODE,',
'       CUSTOMER_UPD_PHONE_AREACODE,',
'       CUSTOMER_UPD_PHONE_NUMBER,',
'       IS_NEW_CUSTOMER,',
'       TO_CHAR(CREATED, ''DY DD.MM.YYYY HH24:MI:SS'') AS CREATED,',
'       LAST_MODIFIED,',
'       -- @ticket FTTH-4404:',
'       CHANGED_BY,',
'       CASE WHEN CHANGED_BY IS NOT NULL -- ein Mensch',
'              OR VERSION IN (',
'                 MIN(VERSION) OVER(PARTITION BY ID) -- erste oder',
'                ,MAX(VERSION) OVER(PARTITION BY ID) -- letzte Version',
'              )',
'              THEN '''' -- relevant',
unistr('              ELSE ''S'' -- SYSTEM, nicht relevant (au\00DFer erster/letzter)'),
'              END AS FILTER,',
'       VERSION,',
'       PROCESS_LOCK,',
'       PROCESS_LOCK_LAST_MODIFIED,',
'       PCK_GLASCONTAINER.fv_user_displayname(changed_by) AS username,',
'       SIEBEL_READY,',
'       SIEBEL_ORDER_NUMBER,',
'       SIEBEL_ORDER_ROWID,',
'       SERVICE_PLUS_EMAIL,',
'       ONT_PROVIDER,',
'       -- neu 2024-08-27: u.a. @ticket FTTH3711',
'       WHOLEBUY_PARTNER,',
'       MANUAL_TRANSFER,',
'       TECHNOLOGY,',
'       CONNECTIVITY_ID, -- @SYNC',
'       RT_CONTACT_DATA_TICKET_ID,',
'       LANDLORD_INFORMATION_REQUIRED,',
'       SIEBEL_MOBIL_COUNTRYCODE,',
'       SIEBEL_MOBIL_AREACODE,',
'       SIEBEL_MOBIL_NUMBER,',
'       UPDATE_CUSTOMER_IN_SIEBEL,',
'       AVAILABILITY_DATE',
'from table (PCK_GLASCONTAINER.fp_order_history(',
'                piv_uuid    => :P20_UUID',
'               ,piv_filter  => :P20_FILTER_AUFTRAGSHISTORIE',
'           )',
'     ) POB',
'  JOIN status_lov                    ON (status_lov.r = POB.state)',
'  LEFT JOIN produkt_lov              ON (produkt_lov.r = POB.TEMPLATEID)',
'  LEFT JOIN router_lov               ON (router_lov.r  = POB.DEVICECATEGORY)',
'  LEFT JOIN router_eigentum_lov      ON (router_eigentum_lov.r = POB.DEVICEOWNERSHIP)',
'  LEFT JOIN installationsservice_lov ON (installationsservice_lov.r = POB.INSTALLATIONSERVICE)'))
,p_plug_source_type=>'NATIVE_IG'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
,p_prn_body_font_family=>'Helvetica'
,p_prn_body_font_weight=>'normal'
,p_prn_body_font_size=>'10'
,p_prn_border_width=>.5
,p_prn_page_header_alignment=>'CENTER'
,p_prn_page_footer_alignment=>'CENTER'
,p_prn_border_color=>'#666666'
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'Die Auftragshistorie wird durch einen synchronen Aufruf des ORDER_HISTORY-Endpunkts bei jedem Laden der Auftragsansicht ermittelt.',
'',
'@ticket FTTH-593, @ticket FTTH-2648, @ticket FTTH-2411, @ticket FTTH-4404.',
'',
unistr('Die Einstellungen f\00FCr dieses IG werden ausgeblendet (siehe Page CSS: div#auftragshistorie_ig_report_settings).'),
unistr('Neue Spalten m\00FCssen im IG als "HTML Expression" dargestellt und in der function diffAuftragshistorie() initialisiert werden. Zum Hinzuf\00FCgen der Spalte in der Ansicht (die f\00FCr den User nicht \00E4nderbar ist, aus gutem Grund) muss kurzfristig das Aktionen')
||unistr('-Men\00FC sichtbar gemacht und der Report inklusive der neuen Spalten abgespeichert werden. Anschlie\00DFend das Aktionen-Men\00FC wieder ausblenden und die Seite 20 damit abspeichern.')))
);
