unistr('2022-08-09: \00C4nderungen, die @HBOEDER an der Definition der Selectliste machen musste, ins PCK_GLASCONTAINER verlagert (weil im Produkt fortan Bindestriche anstatt Unterstriche benutzt werden).'),
unistr('2023-08-17: Item-Name und -Referenzen der Klarheit halber ge\00E4ndert von P20_PROMOTION zu P20_PRODUKT'),
'-- 2023-08-22 @ticket FTTH-2411, war:',
'SELECT d, r FROM TABLE(PCK_GLASCONTAINER.LOV(',
'    piv_name       => ''PRODUKT'', ',
'    piv_parameter1 => :P20_MIN_BANDBREITE,',
'    piv_parameter2 => :P20_MAX_BANDBREITE,',
'    piv_parameter3 => :P20_PRODUKT',
'))'))
);
