'            ]);',
'            $(''#BTN_EXTERNE_AUFTRAGSNUMMER_CLOSE'').removeClass(''u-success'').find(''span.t-Icon'').remove();',
'        } else {',
'            // Erfolgsfall:',
'            apex.item(''P20_EXT_AUFTRAGSNUMMER_TEMP_WS'').setValue(pData);',
'            apex.item(''P20_EXT_AUFTRAGSNUMMER'').setValue(pData);',
'            apex.message.showPageSuccess(''Externe Auftragsnummer '' + ',
'            apex.item(''P20_EXT_AUFTRAGSNUMMER_TEMP_WS'').getValue() +',
'        '' wurde generiert.'');',
'        }',
'        }',
'    ,dataType: ''text''',
'    }',
');',
''))
,p_security_scheme=>wwv_flow_imp.id(244597399936966998)
);
