'       -- 2023-06-14 neu:',
'       ,pov_storno_username            => :P20_STORNO_USERNAME',
'       ,pov_storno_grund               => :P20_STORNO_GRUND',
'       ,pod_storno_datum               => :P20_STORNO_DATUM',
'       -- 2023-07-05 neu:',
'       ,pov_siebel_order_number        => :P20_SIEBEL_AUFTRAGSNUMMER',
'       ,pov_siebel_order_rowid         => :P20_SIEBEL_AUFTRAG_ZEILENNUMMER',
'       ,pov_siebel_ready               => :P20_SIEBEL_READY',
'       ,pov_service_plus_email         => :P20_SERVICE_PLUS_EMAIL',
'       -- 2023-11-30 neu:',
'       ,pov_wholebuy_partner           => :P20_WHOLEBUY_PARTNER',
'       ,pov_manual_transfer            => :P20_MANUAL_TRANSFER',
'       ,pov_technology                 => :P20_TECHNOLOGIE -- zB. "G_FAST". war: :P20 DIENSTTYP',
'       -- 2024-08-01 @ticket FTTH-3727 @SYNC #16:',
'       ,pov_connectivity_id                => :P20_EXT_AUFTRAGSNUMMER',
'       ,pov_rt_contact_data_ticket_id      => :P20_KONTAKTDATEN_AKQUISE_TICKET_ID',
'       ,pov_rt_contact_data_ticket_link    => :P20_KONTAKTDATEN_AKQUISE_TICKET_LINK',
'       ,pov_landlord_information_required  => :P20_EIGENTUEMERDATEN_NOTWENDIG',
'       -- 2024-08-23 @ticket FTTH-3711:',
'    ----,pov_siebel_email                  => :P20_EMAIL_AUFTRAG -- s.u.',
'       ,pov_customer_upd_phone_countrycode => :P20_CUSTOMER_UPD_PHONE_COUNTRYCODE',
'       ,pov_customer_upd_phone_areacode    => :P20_CUSTOMER_UPD_PHONE_AREACODE',
'       ,pov_customer_upd_phone_number      => :P20_CUSTOMER_UPD_PHONE_NUMBER',
'       ,pov_update_customer_in_siebel      => :P20_UPDATE_CUSTOMER_IN_SIEBEL',
'       ,pov_home_id                        => :P20_HOME_ID',
'       ,pov_account_id                     => :P20_SIEBEL_ACCOUNT_ID',
'       ,pod_availability_date              => :P20_AVAILABILITY_DATE',
'    );',
'',
'-- @defect FTTH-4227: Im Falle dass sowohl die SIEBEL-Adresse, als auch die auftragsbezogenen Daten  ',
unistr('-- angezeigt werden sollen, lieferte die obige Abfrage nicht die korrekten Ergebnisse f\00FCr die SIEBEL-Daten.  '),
unistr('-- Die zuletzt hinzugef\00FCgten OUT-Felder k\00F6nnten zum Teil \00FCberfl\00FCssig sein.'),
'-- Die Zuweisung wird im Prozess "Siebel-Daten laden" korrigiert',
'',
'    :P20_EMAIL_AUFTRAG := :P20_CUSTOMER_UPD_EMAIL; -- @ticket FTTH-3711',
'    :P20_IBAN := PCK_GLASCONTAINER.fv_iban_maskiert(:P20_IBAN);',
'    :P20_STATUS_DISPLAY := PCK_GLASCONTAINER.fv_auftragsstatus_display(:P20_STATUS);',
'    :P20_CREATED := to_char(v_created, ''Dy DD.MM.YYYY HH24:MI'');',
'    :P20_LAST_MODIFIED := to_char(v_last_modified, ''DD.MM.YYYY HH24:MI'');',
'    :P20_PROCESS_LOCK_LAST_MODIFIED := to_char(v_process_lock_last_modified, ''DD.MM.YYYY HH24:MI:SS'');',
'    ',
'    IF :P20_SIEBEL_ORDER_NUMBER IS NULL AND :P20_SIEBEL_AUFTRAGSNUMMER IS NOT NULL THEN',
'      :P20_SIEBEL_ORDER_NUMBER := :P20_SIEBEL_AUFTRAGSNUMMER;',
'    END IF;',
'    IF :P20_SIEBEL_ORDER_ROWID IS NULL AND :P20_SIEBEL_AUFTRAG_ZEILENNUMMER IS NOT NULL THEN',
'      :P20_SIEBEL_ORDER_ROWID := :P20_SIEBEL_AUFTRAG_ZEILENNUMMER;',
'    END IF;',
'',
'    :P20_PROMOTION := PCK_GLASCONTAINER.fv_promotion(:P20_PRODUKT);',
'    ',
'    IF :P20_WHOLEBUY_PARTNER IS NOT NULL THEN',
'      :P20_WHOLEBUY_PARTNER_DISPLAY := PCK_GLASCONTAINER.fv_wholebuy_partner_display(:P20_WHOLEBUY_PARTNER);',
'    END IF;',
'',
'    :P20_TECHNOLOGIE_DISPLAY := PCK_GLASCONTAINER.fv_technologie_display(:P20_TECHNOLOGIE); -- neu 2024-09-10',
'    -- @ticket FTTH-3747:',
'    IF :P20_SIEBEL_READY = ''false'' THEN',
'      :P20_TECHNOLOGIE_DISPLAY := :P20_TECHNOLOGIE_DISPLAY || '' (vsl.)''; -- "voraussichtlich"',
'    END IF;',
'    ',
'    -- @ticket FTTH-3837:',
'    :P20_CSS_NOEDIT_LANDLORD :=',
'      CASE WHEN :P20_STATUS <> PCK_GLASCONTAINER.STATUS_CLEARING_LANDLORD_DATA',
'           THEN ''noEdit'' END;',
'',
'    :P20_CSS_NOEDIT_PRODUCT :=',
'      CASE WHEN :P20_STATUS = PCK_GLASCONTAINER.STATUS_CLEARING_LANDLORD_DATA',
'           THEN ''noEdit'' END;',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        --APEX_APPLICATION.STOP_APEX_ENGINE;',
'        apex_util.redirect_url(p_url => apex_page.get_url(',
'            p_application => :APP_ID,',
'            p_page        => 10050',
'        ));',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>':P20_UUID IS NOT NULL'
,p_process_when_type=>'EXPRESSION'
,p_process_when2=>'PLSQL'
,p_internal_uid=>30924161826028504
,p_process_comment=>unistr('L\00E4dt die synchronisierten Daten in die Auftragsfelder des Formulars. Stellt sicher, dass bei jedem Aufrufen der Seite die aktuellen Serverdaten zur Anzeige kommen, selbst wenn unmittelbar zuvor ein REST POST stattgefunden hat.')
);
