wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(231474925833046710)
,p_process_sequence=>60
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Abgeleitete Felder berechnen'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- GEE gilt als erteilt, wenn:',
':P20_ERTEILUNG_GEE := CASE WHEN :P20_GEE_ROLLE = ''OWNER'' ',
'                      AND :P20_ANZAHL_WE IN(''ONE'', ''MORE_THAN_ONE'') ',
'                      AND :P20_WHOLEBUY_PARTNER IS NULL -- @ticket FTTH-XXX',
'                      THEN ''true'' ELSE ''false'' END;',
'',
unistr('-- 2022-09-13: @///kl\00E4ren: Neues Feld IS_NEW_CUSTOMER widerspricht teilweise der bisherigen L\00F6sung, da oft leer'),
'-- :P20_KUNDENSTATUS := CASE WHEN :P20_IS_NEW_CUSTOMER = ''true'' THEN ''N'' ELSE ''B'' END;',
':P20_KUNDENSTATUS := CASE WHEN :P20_CUSTOMER_UPD_EMAIL IS NULL THEN ''N'' ELSE ''B'' END;',
':P20_KUNDENSTATUS_DISPLAY := CASE WHEN :P20_KUNDENSTATUS = ''N'' THEN ''Neukunde'' else ''Bestandskunde'' END;',
'IF :P20_KUNDENSTATUS = ''B'' ',
'-- @defect FTTH-4227:',
'AND NVL(:P20_UPDATE_CUSTOMER_IN_SIEBEL, ''-'') <> ''false''',
'THEN',
'  :P20_EMAIL := :P20_CUSTOMER_UPD_EMAIL;',
'END IF;',
unistr('-- Gr\00FCnde, warum dieser Auftrag NICHT bearbeitet werden darf:'),
'IF :P20_WS_ERRORCODE IS NOT NULL THEN',
'  :P20_CAN_EDIT := :P20_WS_ERRORCODE;',
'ELSE',
'  :P20_CAN_EDIT := CASE :P20_STATUS',
'      WHEN PCK_GLASCONTAINER.STATUS_CANCELLED        THEN ''Auftrag ist gesperrt'' ',
'      WHEN PCK_GLASCONTAINER.STATUS_SIEBEL_PROCESSED THEN ''Auftrag ist abgeschlossen''',
'  END;',
'END IF;',
'-- @ticket FTTH-3837:',
':P20_CAN_EDIT_PRODUCT := ',
'  CASE WHEN :P20_CAN_EDIT IS NOT NULL THEN :P20_CAN_EDIT',
unistr('       WHEN :P20_STATUS = PCK_GLASCONTAINER.STATUS_CLEARING_LANDLORD_DATA THEN ''Eigent\00FCmerdaten fehlen'''),
'  END;',
':P20_CAN_EDIT_LANDLORD := ',
'  CASE WHEN :P20_CAN_EDIT IS NOT NULL THEN :P20_CAN_EDIT',
'       WHEN :P20_STATUS <> PCK_GLASCONTAINER.STATUS_CLEARING_LANDLORD_DATA THEN ''Auftragsstatus nicht CLEARING_LANDLORD_DATA    ''',
'  END;  ',
'',
'  :P20_FILTER_AUFTRAGSHISTORIE := ''R''; -- @ticket FTTH-4404: nur Relevante'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P20_UUID'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>27311775204944420
);
wwv_flow_imp_page.create_page_process(
