,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Vermarktungscluster laden'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  vc vermarktungscluster%rowtype;',
'BEGIN',
'  -- Gibt es Daten zum VMC?',
'  BEGIN',
'    vc := PCK_VERMARKTUNGSCLUSTER.fr_vermarktungscluster(pin_haus_lfd_nr => :P20_HAUS_LFD_NR);',
'  EXCEPTION',
'    WHEN NO_DATA_FOUND THEN NULL;',
'  END;',
'  -- Gefundene Werte zuweisen:',
'  :P20_MIN_BANDBREITE := vc.mindestbandbreite;',
'  :P20_MAX_BANDBREITE := vc.zielbandbreite_geplant;',
'  :P20_VC_STATUS := vc.status;',
'  :P20_VC_WHOLEBUY := vc.wholebuy;',
'  :P20_VC_DNSTTP_LFD_NR := vc.dnsttp_lfd_nr;',
'  ',
unistr('  -- 2024-09-10: Die Technologie aus den Auftragsdaten darf nur dann \00FCberschrieben werden, '),
unistr('  -- wenn der Wert im POB fehlt (das sollte ausschlie\00DFlich f\00FCr stornierte Auftr\00E4ge zutreffen,'),
'  -- da alle anderen mit Release 83 migriert wurden):',
'  IF :P20_STATUS = PCK_GLASCONTAINER.STATUS_CANCELLED ',
'  AND :P20_TECHNOLOGIE IS NULL THEN',
'    :P20_TECHNOLOGIE := PCK_GLASCONTAINER.fv_technologie(:P20_VC_DNSTTP_LFD_NR);',
'    :P20_TECHNOLOGIE_DISPLAY := PCK_GLASCONTAINER.fv_technologie_display(:P20_TECHNOLOGIE);',
'  END IF;',
'  ',
'END; ',
'',
':P20_BANDBREITENINFO := PCK_GLASCONTAINER.fv_get_bandbreiteninfo(:P20_MIN_BANDBREITE, :P20_MAX_BANDBREITE);'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P20_HAUS_LFD_NR'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>28972859718398303
,p_process_comment=>unistr('L\00E4dt Daten zum Vermarktungscluster (Bandbreiten, Technologie), dem die P20_HAUS_LFD_NR zugeordnet ist.')
);
