wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(56534279326052108)
,p_process_sequence=>90
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Siebel-Kontaktdaten laden'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_email_pob VARCHAR2(300);',
'BEGIN',
'    v_email_pob := :P20_EMAIL; -- retten und ggf. unten wiederherstellen',
'    PCK_GLASCONTAINER.P_GET_SIEBEL_KONTAKTDATEN(',
'        -- in der Entwicklung & im Test haben wir hier oft nichts, ',
'        -- und dann sieht das wie ein Programmierfehler aus:',
'         piv_kundennummer            => :P20_KUNDENNUMMER',
'       , pov_ap_email                => :P20_EMAIL',
'       , pov_ap_mobil_laendervorwahl => :P20_LAENDERVORWAHL_SIEBEL',
'       , pov_ap_mobil_onkz           => :P20_VORWAHL_SIEBEL',
'       , pov_ap_mobil_rufnummer      => :P20_TELEFON_SIEBEL',
'    );',
'    -- falls also in Siebel keine Kontaktdaten gefunden wurden (was in PROD unwahrscheinlich ist),',
'    -- dann hole ersatzweise die POB-Kontaktdaten heran (@Flo)',
'    IF :P20_LAENDERVORWAHL_SIEBEL IS NULL AND',
'       :P20_VORWAHL_SIEBEL IS NULL AND   ',
unistr('       :P20_TELEFON_SIEBEL IS NULL THEN   -- //// hierf\00FCr ein Flag einf\00FChren?'),
unistr('       -- f\00FCr Neukunden aus customer'),
'       IF :P20_KUNDENSTATUS = ''N'' THEN',
'           :P20_LAENDERVORWAHL_SIEBEL := :P20_CUSTOMER_PHONE_COUNTRYCODE;',
'           :P20_VORWAHL_SIEBEL        := :P20_CUSTOMER_PHONE_AREACODE;',
'           :P20_TELEFON_SIEBEL        := :P20_CUSTOMER_PHONE_NUMBER;',
'       ELSE  ',
'           :P20_LAENDERVORWAHL_SIEBEL := :P20_CUSTOMER_UPD_PHONE_COUNTRYCODE;',
'           :P20_VORWAHL_SIEBEL        := :P20_CUSTOMER_UPD_PHONE_AREACODE;',
'           :P20_TELEFON_SIEBEL        := :P20_CUSTOMER_UPD_PHONE_NUMBER;',
'       END IF;',
'    END IF;',
'',
'    IF :P20_EMAIL IS NULL THEN  ',
'      :P20_EMAIL := COALESCE(v_email_pob, :P20_CUSTOMER_UPD_EMAIL); -- damit in der Entwicklung wenigstens irgendwas zu sehen ist',
'    END IF;',
'',
'END;',
'-- Telefonnummern konkatenieren, @ticket FTTH-3711:',
':P20_RUFNUMMER_SIEBEL_DISPLAY := PCK_RUFNUMMER.FV_E164(',
'                                 :P20_LAENDERVORWAHL_SIEBEL',
'                              || :P20_VORWAHL_SIEBEL',
'                              || :P20_TELEFON_SIEBEL);'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>6160686384839603
,p_process_comment=>'@ticket FTTH-3711: In jedem Fall die Kontaktdaten aus SIEBEL anzeigen'
);
