wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(300435694209056755)
,p_plug_name=>unistr('M\00F6gliche Dubletten')
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_include_in_reg_disp_sel_yn=>'Y'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'with kunden as (',
'  select id as uuid',
'       , customernumber as kundennummer',
'       , account_iban as iban',
'       , upper(customer_name_last || '','' || customer_name_first) as "NAME"',
'     from ftth_ws_sync_preorders',
'    where state = ''IN_REVIEW''',
'      and customernumber IS NOT NULL',
')',
',',
'pob_dubletten as (',
'select /*+materialize*/ uuid, count(*) as anzahl from (',
'select pob0.uuid as uuid',
'  from kunden pob0',
'     , kunden pob1',
' where -- nicht mit sich selbst vergleichen:',
'       pob0.uuid         <> pob1.uuid   ',
'   and pob0.kundennummer <> pob1.kundennummer',
'   --- Wo gibt es die gleiche IBAN?',
'   and (pob0.iban = pob1.iban',
'   --- wo den gleichen Namen?',
'    or pob0.name  = pob1.name)',
') group by uuid   ',
')',
'select PRE.ID,',
'       PRE.ID AS UUID,',
'       TEMPLATEID,',
'       DEVICECATEGORY,',
'       DEVICEOWNERSHIP,',
'       INSTALLATIONSERVICE,',
'       HOUSECONNECTIONPRICE,',
'       SUMM_ORDERSUMMARYFILEID,',
'       STATE,',
'       STATE AS STATUS,',
'       VKZ,',
'       CLIENT,',
'       CUSTOMERNUMBER,',
'       CUSTOMER_BUSINESSNAME,',
'       CUSTOMER_SALUTATION,',
'       CUSTOMER_TITLE,',
'       CUSTOMER_NAME_FIRST,',
'       CUSTOMER_NAME_LAST,',
'       CUSTOMER_BIRTHDATE,',
'       CUSTOMER_EMAIL,',
'       CUSTOMER_PHONE_COUNTRYCODE,',
'       CUSTOMER_PHONE_AREACODE,',
'       CUSTOMER_PHONE_NUMBER,',
'       HOUSESERIALNUMBER,',
'       CUSTOMER_RESIDENTSTATUS,',
'       INSTALL_ADDR_COUNTRY,',
'       INSTALL_ADDR_ZIPCODE,',
'       INSTALL_ADDR_CITY,',
'       INSTALL_ADDR_STREET,',
'       INSTALL_ADDR_HOUSENUMBER,',
'       INSTALL_ADDR_ADDITION,',
'       PROVIDERCHG_CURRENT_PROVIDER,',
'       PROVIDERCHG_KEEP_PHONE_NUMBER,',
'       PROVIDERCHG_PHONE_COUNTRYCODE,',
'       PROVIDERCHG_PHONE_AREACODE,',
'       PROVIDERCHG_PHONE_NUMBER,',
'       PROVIDERCHG_CONTRACT_CANCELLED,',
'       PROVIDERCHG_CANCELLATION_DATE,',
'       PROVIDERCHG_OWNER_SALUTATION,',
'       PROVIDERCHG_OWNER_NAME_FIRST,',
'       PROVIDERCHG_OWNER_NAME_LAST,',
'       ACCOUNT_SEPAMANDATE,',
'       ACCOUNT_HOLDER,',
'       LANDLORD_NAME_LAST,',
'       ACCOUNT_IBAN,',
'       LANDLORD_NAME_FIRST,',
'       LANDLORD_EMAIL,',
'       LANDLORD_TITLE,',
'       LANDLORD_ADDR_CITY,',
'       LANDLORD_ADDR_STREET,',
'       LANDLORD_ADDR_COUNTRY,',
'       LANDLORD_ADDR_ZIPCODE,',
'       LANDLORD_ADDR_HOUSENUMBER,',
'       LANDLORD_ADDR_ADDITION,',
'       LANDLORD_LEGALFORM,',
'       LANDLORD_SALUTATION,',
'       LANDLORD_PHONE_NUMBER,',
'       LANDLORD_PHONE_AREACODE,',
'       LANDLORD_PHONE_COUNTRYCODE,',
'       LANDLORD_BUSINESSORNAME,',
'       PROP_RESIDENTIAL_UNIT,',
'       PROP_OWNER_ROLE,',
'       LANDLORD_AGREED,',
'       SUMM_PRECONTRACTINFORMATION,',
'       SUMM_GENERALTERMSANDCONDITIONS,',
'       SUMM_WAIVERIGHTOFREVOCATION,',
'       SUMM_EMAILMARKETING,',
'       SUMM_PHONEMARKETING,',
'       SUMM_SMSMMSMARKETING,',
'       SUMM_MAILMARKETING,',
'       CUSTOMER_PREV_ADDR_STREET,',
'       CUSTOMER_PREV_ADDR_HOUSENUMBER,',
'       CUSTOMER_PREV_ADDR_ADDITION,',
'       CUSTOMER_PREV_ADDR_ZIPCODE,',
'       CUSTOMER_PREV_ADDR_CITY,',
'       CUSTOMER_PREV_ADDR_COUNTRY,',
'       CUSTOMER_UPD_EMAIL,',
'       CUSTOMER_UPD_PHONE_COUNTRYCODE,',
'       CUSTOMER_UPD_PHONE_AREACODE,',
'       CUSTOMER_UPD_PHONE_NUMBER,',
'    -- CUSTOMER_PASSWORD, -- entfernt 2025-01-21',
'       APEX$SYNC_STEP_STATIC_ID,',
'       APEX$ROW_SYNC_TIMESTAMP,',
'       CASE WHEN PROVIDERCHG_CURRENT_PROVIDER IS NULL THEN 0 ELSE 1 END AS ANBIETERWECHSEL,',
'       CASE WHEN PROP_OWNER_ROLE = ''OWNER'' AND PROP_RESIDENTIAL_UNIT IN (''ONE'', ''MORE_THAN_ONE'') THEN 1 ELSE 0 END AS GEE_ERTEILT, -- 2022-09-13 @fschoenemeyer',
'       CASE WHEN IS_NEW_CUSTOMER = ''true'' THEN ''N'' ELSE ''B'' END AS KUNDENSTATUS, -- Neukunde, Bestandskunde',
'       IS_NEW_CUSTOMER,',
'       CREATED,',
'       LAST_MODIFIED,',
'       VERSION,',
'       PROCESS_LOCK,',
'       PROCESS_LOCK AS PROCESS_LOCK_DISPLAY,',
'       PROCESS_LOCK_LAST_MODIFIED,',
'       -- 2022-12-27: Fuzzy!Double-Suche anbinden:',
'       (SELECT COUNT(DISTINCT KUNDENNUMMER) ',
'          FROM FTTH_PREORDERS_FUZZYDOUBLE F',
'          JOIN FTTH_WS_SYNC_PREORDERS P ',
'            ON (P.ID = F.FTTH_ID)',
'          LEFT JOIN FTTH_DUBLETTEN_BEWERTUNG BW',
'            ON (BW.KNR0 = PRE.CUSTOMERNUMBER',
'            AND BW.KNR1 = F.KUNDENNUMMER',
'            AND AKTUELL = 1)',
'         WHERE F.FTTH_ID = PRE.ID',
'           AND F.STATUS IS NULL',
unistr('           AND NVL(BW.BEWERTUNG, ''W'') = ''W'' -- Wiedervorlage oder \00FCberhaupt keine Bewertung vorhanden'),
'           AND P.state = ''IN_REVIEW''',
'       ) AS FUZZY_COUNT,',
'     (SELECT anzahl FROM POB_DUBLETTEN WHERE POB_DUBLETTEN.uuid = PRE.id) as POB_COUNT',
'  FROM FTTH_WS_SYNC_PREORDERS PRE',
' WHERE PRE.state = ''IN_REVIEW''',
'   AND PRE.customernumber IS NOT NULL'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_required_role=>wwv_flow_imp.id(244597399936966998)
,p_plug_display_condition_type=>'ITEM_IS_NULL'
,p_plug_display_when_condition=>'P40_UUID'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
