,p_plug_header=>unistr('<p>Die folgenden Dubletten-Kandidaten wurden noch nicht abschlie\00DFend bewertet:</p>')
,p_plug_comment=>unistr('Report mit allen Preorderbuffer-Auftr\00E4gen und der Anzahl der dazugeh\00F6rigen Dubletten, die noch nicht abschlie\00DFend bearbeitet worden sind')
