'  var beschreibungTabelle = beschreibung.replace(/\[/g, "<");',
'      beschreibungTabelle = beschreibungTabelle.replace(/\]/g, ">");',
'///const score = $liste.data(''score'');',
'const $auswahl = $(''option:selected'', $liste);',
'const neueBewertung = $auswahl.attr(''value''); // zB. ''K''',
'const alteBewertung = $liste.data(''bewertung'');',
'const text = $auswahl.text();',
'const kommentar = '''';',
'apex.item(''P40_KNR1'').setValue(knr1);',
'$(''#knr0Info'').html(apex.item(''P40_KOPFDATEN'').getValue());',
'$(''#knr1Info'').html(beschreibungTabelle);',
'// Hier nur reagieren, wenn NICHT auf Kommentar... geklickt wurde',
