,p_step_title=>'Fuzzy-Direktabfrage'
,p_autocomplete_on_off=>'OFF'
,p_group_id=>wwv_flow_imp.id(77868900765297320)
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'18'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(296768738751326814)
,p_plug_name=>'Fuzzy-Suchergebnisse'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>20
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_new_grid_row=>false
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH FUZZY AS (',
'SELECT  ''PHO'' AS SUCHTYP',
'       ,row_id',
'       ,score',
'       ,vorname',
'       ,nachname',
'       ,geburtsdatum',
'       ,firmenname',
'       ,strasse',
'       ,hausnummer',
'       ,plz',
'       ,ort',
'       ,iban',
'FROM TABLE(',
'    PCK_FUZZYDOUBLE.ft_phonetic_search(',
'         piv_nachname   => :P42_NACHNAME',
'        ,piv_vorname    => :P42_VORNAME',
'        ,piv_firmenname => :P42_FIRMENNAME',
'        ,piv_strasse    => :P42_STRASSE',
'        ,piv_hausnummer => :P42_HAUSNUMMER',
'        ,piv_plz        => :P42_PLZ',
'        ,piv_ort        => :P42_ORT',
'        ,pin_ignore_service_errors => :P10100_IGNORE_FUZZY_SERVICE_ERRORS',
'        )',
'    )',
'UNION ALL',
'SELECT ''IBAN'' AS SUCHTYP',
'       ,row_id',
'       ,score',
'       ,vorname',
'       ,nachname',
'       ,geburtsdatum',
'       ,firmenname',
'       ,strasse',
'       ,hausnummer',
'       ,plz',
'       ,ort',
'       ,iban',
'   FROM TABLE(PCK_FUZZYDOUBLE.ft_doublet_check_bank(',
'                 piv_iban => :P42_IBAN',
'               , pin_ignore_service_errors => :P10100_IGNORE_FUZZY_SERVICE_ERRORS',
'           )',
'       )',
')',
'SELECT  FUZZY.SUCHTYP',
'       ,FUZZY.row_id',
'       ,FUZZY.score',
'       ,TO_CHAR(NULL) AS KUNDENNUMMER',
'       ,FUZZY.vorname',
'       ,FUZZY.nachname',
'       ,FUZZY.geburtsdatum',
'       ,FUZZY.firmenname',
'       ,FUZZY.strasse',
'       ,FUZZY.hausnummer',
'       ,FUZZY.plz',
'       ,FUZZY.ort',
'       ,FUZZY.iban',
'   FROM FUZZY',
'---   LEFT JOIN v_apx_gc_customerdata@siebp.netcologne.intern@siebel_inf SIEBEL -- 2023-02-23: knallt in der Produktion',
'---     ON (FUZZY.row_id = SIEBEL.GLOBAL_ID)',
' WHERE FUZZY.score >= COALESCE(:P10100_FUZZY_MIN_SCORE_PHO, 80) -- sonst ufert das aus!'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_display_condition_type=>'REQUEST_EQUALS_CONDITION'
,p_plug_display_when_condition=>'FUZZY_DIREKTABFRAGE'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
