,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
,p_prn_body_font_family=>'Helvetica'
,p_prn_body_font_weight=>'normal'
,p_prn_body_font_size=>'10'
,p_prn_border_width=>.5
,p_prn_page_header_alignment=>'CENTER'
,p_prn_page_footer_alignment=>'CENTER'
,p_prn_border_color=>'#666666'
,p_plug_header=>'<p>Fuzzy-Rohdaten</p>'
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('Die Fuzzy-Abfrage wird nur ausgef\00FChrt, wenn der Request FUZZY lautet. @next: Dieses SQL f\00FChrt in PROD zu Internal Server Error, daher brauchen wir eine Pipelined Function, die die SIEBEL-Ergebnisse einzeln hinzuf\00FCgt:'),
'WITH FUZZY AS (',
'SELECT  ''PHO'' AS SUCHTYP',
'       ,row_id',
'       ,score',
'       ,vorname',
'       ,nachname',
'       ,geburtsdatum',
'       ,firmenname',
'       ,strasse',
'       ,hausnummer',
'       ,plz',
'       ,ort',
'       ,iban',
'FROM TABLE(',
'    PCK_FUZZYDOUBLE.ft_phonetic_search(',
'         piv_nachname   => :P42_NACHNAME',
'        ,piv_vorname    => :P42_VORNAME',
'        ,piv_firmenname => :P42_FIRMENNAME',
'        ,piv_strasse    => :P42_STRASSE',
'        ,piv_hausnummer => :P42_HAUSNUMMER',
'        ,piv_plz        => :P42_PLZ',
'        ,piv_ort        => :P42_ORT',
'        )',
'    )',
'UNION ALL',
'SELECT ''IBAN'' AS SUCHTYP',
'       ,row_id',
'       ,score',
'       ,vorname',
'       ,nachname',
'       ,geburtsdatum',
'       ,firmenname',
'       ,strasse',
'       ,hausnummer',
'       ,plz',
'       ,ort',
'       ,iban',
'   FROM TABLE(PCK_FUZZYDOUBLE.ft_doublet_check_bank(piv_iban => :P42_IBAN))',
')',
'SELECT  FUZZY.SUCHTYP',
'       ,FUZZY.row_id',
'       ,FUZZY.score',
'       ,SIEBEL.KUNDENNUMMER',
'       ,COALESCE(SIEBEL.vorname, FUZZY.vorname) AS vorname',
'       ,COALESCE(SIEBEL.nachname, FUZZY.nachname) AS nachname',
'       ,COALESCE(SIEBEL.geburtsdatum, FUZZY.geburtsdatum) AS geburtsdatum',
'       ,COALESCE(SIEBEL.FIRMENNAME, FUZZY.firmenname) AS firmenname',
'       ,COALESCE(SIEBEL.STRASSE, FUZZY.strasse) AS strasse',
'       ,COALESCE(TRIM(SIEBEL.HAUSNR_VON || '' '' || SIEBEL.HAUSNR_ZUSATZ_VON), FUZZY.hausnummer) AS hausnummer',
'       ,COALESCE(SIEBEL.plz, FUZZY.plz) AS plz',
'       ,COALESCE(SIEBEL.ort, FUZZY.ort) AS ort',
'       ,COALESCE(SIEBEL.iban, FUZZY.iban) AS iban',
'   FROM FUZZY',
'   LEFT JOIN v_apx_gc_customerdata@siebp.netcologne.intern@siebel_inf SIEBEL',
'     ON (FUZZY.row_id = SIEBEL.GLOBAL_ID)',
' WHERE FUZZY.score >= 80 -- sonst ufert das aus!'))
);
