wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(229253109486194619)
,p_plug_name=>'Dubletten in Siebel'
,p_region_name=>'dublettensuche_ergebnisse_siebel'
,p_parent_plug_id=>wwv_flow_imp.id(259132289803772297)
,p_region_css_classes=>'dublettensuche ergebnisse'
,p_region_template_options=>'#DEFAULT#:margin-top-lg'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>20
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('-- ACHTUNG: Inhaltlich dieselbe Abfrage muss im Page Submit von Step 2 ausgef\00FChrt werden,'),
unistr('-- damit der Wizard entscheiden kann, ob dieser Dubletten-Report \00FCberhaupt angezeigt wird.'),
'SELECT',
'    src,',
'    CASE src',
'      WHEN ''PHO'' THEN ''Adresse''',
'      WHEN ''BNK'' THEN ''IBAN''',
'    END AS src_display,',
'    row_id AS ID,',
'    kundennummer,',
'    rule_number,',
'    score,',
'    vorname,',
'    nachname,',
'    geburtsdatum,',
'    firmenname,',
'    trim(strasse || '' '' || hausnummer) as strasse_hausnr,',
'    plz,',
'    ort,',
'    adresse_komplett,',
'    pck_glascontainer.fv_iban_maskiert(iban) as iban,',
'    ''<button type="button" class="t-Button options" data-src="'' || src || ''" data-id="'' || row_id || ''" data-knr="'' || kundennummer || ''">weiter mit diesem Bestandskunden</button>'' as button_option',
'FROM TABLE (',
'    ---PCK_FUZZYDOUBLE.ft_vorbestellung_dublettencheck( -- @date 2024-06-18 ersetzt durch:',
'       PCK_GLASCONTAINER_ORDER.ft_vorbestellung_dublettencheck(',
'              piv_nachname     => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_NACHNAME ELSE :P100_SIEBEL_NACHNAME END',
'            , piv_vorname      => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_VORNAME ELSE :P100_SIEBEL_VORNAME END',
'            , pid_geburtsdatum => TO_DATE(CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_GEBURTSDATUM ELSE :P100_SIEBEL_GEBURTSDATUM END)',
'            , piv_firmenname   => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_FIRMENNAME ELSE :P100_SIEBEL_FIRMENNAME END',
'         --   , piv_strasse      => :P100_STRAV_STRASSE',
'         --   , piv_hausnummer   => TRIM(:P100_STRAV_HAUSNR || '' '' || :P100_STRAV_HAUSNR_ZUSATZ)',
'         --   , piv_plz          => :P100_STRAV_PLZ',
'         --   , piv_ort          => :P100_STRAV_ORT',
'            , piv_iban         => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_IBAN ELSE :P100_SIEBEL_IBAN END',
'            , pin_ignore_service_errors => :P10100_IGNORE_FUZZY_SERVICE_ERRORS',
'            , piv_suchbereich  => ''SIE''',
'       )',
'    )',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_display_condition_type=>'EXPRESSION'
,p_plug_display_when_condition=>'NVL(:P100_ANZAHL_DUBLETTEN_SIE, 0) > 0'
,p_plug_display_when_cond2=>'PLSQL'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>'Potenzielle Dubletten'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
,p_prn_body_font_family=>'Helvetica'
,p_prn_body_font_weight=>'normal'
,p_prn_body_font_size=>'10'
,p_prn_border_width=>.5
,p_prn_page_header_alignment=>'CENTER'
,p_prn_page_footer_alignment=>'CENTER'
,p_prn_border_color=>'#666666'
,p_plug_header=>unistr('<h5>\00C4hnliche Daten in Siebel:</h5>')
,p_required_patch=>wwv_flow_imp.id(254911487918372194)
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'Der Siebel-Report soll nur angezeigt werden, wenn Dubletten vorliegen (nicht: leer). Das bedingt eine Vorabfrage, siehe SQL.',
unistr('Der Kontrollbereich des IR wird per CSS ausgeblendet, da er st\00F6rt ("a-MediaBlock a-IRR-controlsContainer")')))
