'       :P100_NEUKUNDE_NACHNAME AS NACHNAME,',
'       TO_DATE(:P100_NEUKUNDE_GEBURTSDATUM) AS GEBURTSDATUM,',
'       :P100_NEUKUNDE_FIRMENNAME AS FIRMENNAME,',
'       TRIM(:P100_STRAV_STRASSE || '' '' || :P100_STRAV_HAUSNR || '' '' || :P100_STRAV_HAUSNR_ZUSATZ) AS STRASSE_HAUSNR,',
'       :P100_STRAV_PLZ AS PLZ,',
'       :P100_STRAV_ORT AS ORT,',
'       PCK_ADRESSE.ADRESSE_KOMPLETT(',
'              piv_strasse                 => :P100_STRAV_STRASSE',
'            , piv_hausnummer              => :P100_STRAV_HAUSNR',
'            , piv_hausnummer_zusatz       => :P100_STRAV_HAUSNR_ZUSATZ',
'            , piv_hausnummer_bis          => NULL -- ////// danach im Formular suchen!',
'            , piv_hausnummer_zusatz_bis   => NULL -- ////// danach im Formular suchen!',
'            , piv_gebaeudeteil            => NULL -- ////// danach im Formular suchen!',
'            , piv_plz                     => :P100_STRAV_PLZ',
'            , piv_ort                     => :P100_STRAV_ORT',
'            , piv_ortsteil                => NULL -- ////// danach im Formular suchen!',
'            , piv_land                    => NULL',
'       ) AS ADRESSE_KOMPLETT,',
'       :P100_NEUKUNDE_IBAN AS IBAN,',
'       ''<button type="button" class="t-Button options" data-src="INP">keine Dublette &ndash; weiter als Neukunde</button>'' as button_option',
'  FROM DUAL',
'',
''))
