'    plz,',
'    ort,',
'    adresse_komplett,',
'    pck_glascontainer.fv_iban_maskiert(iban) as iban,',
'    ''<a href="'' || ',
'    APEX_PAGE.GET_URL (',
'            p_page   => 20,',
'            p_items  => ''P20_UUID'',',
'            p_values => row_id,',
'            p_request => ''POB_ORDER'',',
'            p_clear_cache => 20',
'    )',
'    || ''" target="_blank" title="Auftrag in neuem Tab ansehen..."><span class="fa fa-eye"></span></a>'' AS link_glascontainer,',
'    ''<button type="button" class="t-Button options" data-src="'' || src || ''" data-id="'' || row_id || ''" data-knr="'' || kundennummer || ''">weiter mit diesem '' ',
'    || CASE WHEN kundennummer IS NULL THEN ''Neukunden'' ELSE ''Bestandskunden'' END || ''</button>'' as button_option',
'FROM TABLE (',
'       ---PCK_FUZZYDOUBLE.ft_vorbestellung_dublettencheck( -- @date 2024-06-18 ersetzt durch:',
'       PCK_GLASCONTAINER_ORDER.ft_vorbestellung_dublettencheck(',
'              piv_nachname     => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_NACHNAME ELSE :P100_SIEBEL_NACHNAME END',
'            , piv_vorname      => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_VORNAME ELSE :P100_SIEBEL_VORNAME END',
'            , pid_geburtsdatum => TO_DATE(CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_GEBURTSDATUM ELSE :P100_SIEBEL_GEBURTSDATUM END)',
'            , piv_firmenname   => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_FIRMENNAME ELSE :P100_SIEBEL_FIRMENNAME END',
'         --   , piv_strasse      => :P100_STRAV_STRASSE',
'         --   , piv_hausnummer   => TRIM(:P100_STRAV_HAUSNR || '' '' || :P100_STRAV_HAUSNR_ZUSATZ)',
'         --   , piv_plz          => :P100_STRAV_PLZ',
'         --   , piv_ort          => :P100_STRAV_ORT',
'            , piv_iban         => CASE WHEN :P100_KUNDENSTATUS = ''N'' THEN :P100_NEUKUNDE_IBAN ELSE :P100_SIEBEL_IBAN END',
'            , pin_ignore_service_errors => :P10100_IGNORE_FUZZY_SERVICE_ERRORS',
'            , piv_suchbereich  => ''POB''',
'       )',
'    )',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_display_condition_type=>'EXPRESSION'
,p_plug_display_when_condition=>'NVL(:P100_ANZAHL_DUBLETTEN_POB, 0) > 0'
,p_plug_display_when_cond2=>'PLSQL'
,p_plug_header=>unistr('<h5>\00C4hnliche Daten im Preorder-Buffer:</h5>')
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'Der POB-Report soll nur angezeigt werden, wenn Dubletten vorliegen (nicht: leer). Das bedingt eine Vorabfrage, siehe SQL.',
unistr('Der Kontrollbereich des IR wird per CSS ausgeblendet, da er st\00F6rt ("a-MediaBlock a-IRR-controlsContainer")')))
);
