,p_plug_template=>4501440665235496320
,p_plug_display_sequence=>10
,p_plug_display_point=>'SUB_REGIONS'
,p_plug_source=>unistr('<p><strong>Um das Wohngeb\00E4ude &KUNDENREFERENZ_GEN. an das Glasfasernetz von &P100_MANDANT_DISPLAY. anschlie\00DFen zu k\00F6nnen, wird die Grundst\00FCckseigent\00FCmererkl\00E4rung (GEE) ben\00F6tigt.</strong></p>')
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
