wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(233145645498505871)
,p_plug_name=>unistr('GEE Eigent\00FCmer (Text unten)')
,p_parent_plug_id=>wwv_flow_imp.id(233145356375505868)
,p_region_template_options=>'#DEFAULT#:margin-bottom-lg'
,p_plug_template=>4501440665235496320
,p_plug_display_sequence=>30
,p_plug_grid_column_span=>4
,p_plug_display_column=>3
,p_plug_display_point=>'SUB_REGIONS'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<p>',
unistr('    Ich bin damit einverstanden, dass die &P100_MANDANT_DISPLAY. GmbH auf meinem Grundst\00FCck sowie an und in den darauf befindlichen Geb\00E4uden '),
unistr('    alle Vorrichtungen anbringt, die erforderlich sind, um Zug\00E4nge zu ihrem \00F6ffentlichen Telekommunikationsnetz auf dem betreffenden '),
unistr('    oder einem benachbarten Grundst\00FCck und in den darauf befindlichen Geb\00E4uden einzurichten, zu pr\00FCfen und instand zu halten. '),
unistr('    Dieses Recht erstreckt sich auch auf vorinstallierte Hausverkabelungen. Die Inanspruchnahme des Grundst\00FCcks durch Vorrichtungen '),
unistr('    darf nur zu einer notwendigen und zumutbaren Belastung f\00FChren. Die &P100_MANDANT_DISPLAY. GmbH verpflichtet sich, '),
unistr('    unbeschadet bestehender gesetzlicher oder vertraglicher Anspr\00FCche, mein Grundst\00FCck und die darauf befindlichen Geb\00E4ude wieder '),
unistr('    ordnungsgem\00E4\00DF instand zu setzen, soweit das Grundst\00FCck und/oder die Geb\00E4ude durch Vorrichtungen zur Einrichtung, Instandhaltung oder Erweiterung '),
unistr('    von Zug\00E4ngen zu ihrem \00F6ffentlichen Telekommunikationsnetz auf dem betreffenden oder einem benachbarten Grundst\00FCck und/oder '),
unistr('    in den darauf befindlichen Geb\00E4uden infolge der Inanspruchnahme durch die &P100_MANDANT_DISPLAY. GmbH besch\00E4digt worden sind. '),
unistr('    Im Rahmen der technischen M\00F6glichkeiten und der bestehenden Sicherheitsanforderungen wird die &P100_MANDANT_DISPLAY. GmbH '),
'    vorinstallierte Hausverkabelungen nutzen. Die &P100_MANDANT_DISPLAY. GmbH wird die von ihr errichteten Vorrichtungen verlegen oder &ndash; ',
unistr('    soweit sie nicht das Grundst\00FCck versorgen und eine Verlegung nicht ausreicht &ndash; entfernen, wenn sie einer ver\00E4nderten Nutzung '),
unistr('    des Grundst\00FCcks entgegenstehen und ihr Verbleib an der bisherigen Stelle nicht mehr zumutbar ist. Die Kosten f\00FCr die Entfernung oder Verlegung '),
unistr('    tr\00E4gt die &P100_MANDANT_DISPLAY. GmbH. Dies gilt nicht f\00FCr Vorrichtungen, die ausschlie\00DFlich das Grundst\00FCck versorgen, wenn nicht gleichzeitig '),
unistr('    \00C4nderungen am \00F6ffentlichen Telekommunikationsnetz erforderlich sind.'),
'</p>'))
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
