,p_plug_name=>unistr('CSS f\00FCr autosuggest')
,p_plug_display_sequence=>10
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'.autocomplete {',
'  position: relative;',
'  display: inline-block;',
