wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(235652826625458226)
,p_plug_name=>unistr('JavaScript f\00FCr autosuggest')
,p_plug_display_sequence=>20
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var adresscheck = {};',
'var currentFocus;',
'var autocompleteListe;',
'var suggestlisteOffen;',
'',
'// Auswertung keyCode:',
'function isBackpaceEinfg(k) {return k == 8 || k == 46}',
'function isNumber(k) {return (k >= 48 && k <= 57) || (k >= 96 && k <= 105)}',
'function isLetter(k) {return k >= 65 || k == 32}',
'',
'',
'function autocomplete(suchbereich, suchItem, suggestItem, jumpToItem) {',
'    switch(suchbereich) {',
'        case ''plz'':',
'            suchItem.addEventListener("keyup", function(e) { /// ersetzen durch "input" anstatt "keyup"',
'                if(!(isNumber(e.keyCode) || isBackpaceEinfg(e.keyCode))) {',
'                    return;',
'                }',
'                autosuggest(suchbereich, suchItem, suggestItem, jumpToItem);',
'            });',
'            suchItem.addEventListener("paste", function(e) {',
unistr('                // eine kurze Wartezeit, denn ansonsten w\00FCrde nur der Wert _vor_ dem Pasten gefunden:'),
'                setTimeout(function(){',
'                    autosuggest(suchbereich, e.target, suggestItem, jumpToItem);',
'                }, 10);',
'            });            ',
'            break;',
'        case ''ort'':',
'            suchItem.addEventListener("keyup", function(e) {',
'                if(!(isLetter(e.keyCode) || isBackpaceEinfg(e.keyCode))) {',
'                    return;',
'                }',
'                autosuggest(suchbereich, suchItem, suggestItem, jumpToItem);',
'            });        ',
'            break;            ',
'        case ''str'':',
'            suchItem.addEventListener("keyup", function(e) {',
'                if(!(isLetter(e.keyCode) || isBackpaceEinfg(e.keyCode))) {',
'                    return;',
'                }',
'                autosuggest(suchbereich, suchItem, suggestItem, jumpToItem);',
'            });',
'            suchItem.addEventListener("paste", function(e) {',
'                // Wartezeit, s.o.',
'                setTimeout(function(){',
'                    autosuggest(suchbereich, e.target, suggestItem, jumpToItem);',
'                }, 10);',
'            });                 ',
'            break;',
'        default:',
'            break;',
'    }',
'  ',
'  suchItem.addEventListener("keydown", function(e) {',
'    var x = document.getElementById(this.id + "autocomplete-list");',
'    if (x) x = x.getElementsByTagName("div");',
'    if (e.keyCode == 40) {',
'      // arrowDown',
'      currentFocus++;',
'      addActive(x);',
'    } else if (e.keyCode == 38) {',
'      // arrowUp',
'      currentFocus--;',
'      addActive(x);',
'    } else if (e.keyCode == 13) {',
'      // ENTER',
'      e.preventDefault();',
'      if (currentFocus > -1) {',
'        // Klick simulieren: "Cannot read properties of undefined (reading ''click'')" bei Eingabe von Enter ohne Liste',
'        if (x) x[currentFocus].click();',
'      }',
'    } else if (e.keyCode == 9) {',
'      // TAB',
'      if(suggestlisteOffen) {',
'        e.preventDefault();',
'        if (currentFocus > -1) {',
'            if (x) x[currentFocus].click();',
'        }        ',
'      }',
'    }',
'',
'    document.addEventListener("click", function (e) {',
'        closeAllLists();',
'    });    ',
'',
'  }); // /keydown listener',
'} // / autocomplete function',
'',
'',
'function autosuggest(suchbereich, suchItem, suggestItem, jumpToItem) {',
'    if(adresscheck === ''-'') return;',
'    var url;',
'',
'    switch(suchbereich) {',
'        case ''plz'': var zipCode = suchItem.value;',
'                    if(zipCode.length < 3 || zipCode.length > 5) {',
'                        closeAllLists();',
'                        return;',
'                    };',
'                    url = ''https://www.netcologne.de/api/dss-core-addresscheck/address-check/zipcodes?mode=LOCAL&zipCode='' + zipCode;',
'                    break;',
'        case ''ort'': ///@weiter: funktioniert nicht, da es keinen cities-Endpunkt gibt',
'                    return;',
'',
'                    ',
'                    var ort = suchItem.value;',
'                    var zipCode = suggestItem.value;',
'                    if(ort.length < 3 || zipCode.length < 3 || zipCode.length > 5) return;',
'                    url = ''https://www.netcologne.de/api/dss-core-addresscheck/address-check/zipcodes?mode=LOCAL&zipCode='' + zipCode;',
'                    break;',
'        case ''str'': var street = suchItem.value;',
'                    var zipCode = suggestItem.value;',
'                    if(street.length == 0) {',
'                        closeAllLists();',
'                        return;',
'                    };',
'                    if(zipCode.length !== 5) return;',
'                    url = ''https://www.netcologne.de/api/dss-core-addresscheck/address-check/streets?mode=LOCAL&zip='' + zipCode + ''&street='' + street;',
'                    break;',
'        default: break;',
'    }',
'    var request = new XMLHttpRequest();',
'    request.open(''GET'', url, true);',
'    request.onload = function () {',
'        try{',
'            var results = JSON.parse(this.response);',
'            if (request.status >= 200 && request.status < 400) {',
'                switch(suchbereich) {',
'                    case ''plz'': adresscheck.plz = results; break;',
'                    case ''ort'': adresscheck.ort = results; break;',
'                    case ''str'': adresscheck.str = results; break;',
'                    default: break;',
'                }',
'            } else {',
'                console.warn(''Unerwarteter AJAX-Status:'', request.status, ''url='', url)',
'            }',
'        } catch{',
'            if (request.status !== 204)',
'            console.warn(''Fehler bei onload: results='', results, ''status='', request.status)',
'        }',
'        suggestliste(suchbereich, suchItem, suggestItem, jumpToItem);',
'    };',
'    request.send();',
'}',
'',
'',
'',
'function suggestliste(suchbereich, input1, input2, input3) {',
'    var divA, divB, i;',
'    var val = input1.value;',
'    closeAllLists();',
'',
'    switch(suchbereich) {',
'        case ''plz'' : autocompleteListe = adresscheck.plz; break;',
'        case ''ort'' : autocompleteListe = adresscheck.plz; break;',
'        case ''str'' : autocompleteListe = adresscheck.str; break;',
'    }',
'      if(!autocompleteListe) return false;',
'      ',
'      suggestlisteOffen = true;',
'      ',
'      divA = document.createElement("DIV");',
'      divA.setAttribute("id", input1.id + "autocomplete-list");',
'      divA.setAttribute("class", "autocomplete-items");',
'      input1.parentNode.appendChild(divA);',
'      var listValue;',
'      for (i = 0; i < autocompleteListe.length; i++) {',
'        var listValue;',
'        var helpValue;',
'        switch(suchbereich) {',
'            case ''plz'' : listValue = autocompleteListe[i].zipCode; ',
'                         helpValue = autocompleteListe[i].city;',
'                         break;',
'            case ''ort'' : listValue = autocompleteListe[i].city;',
'                         helpValue = autocompleteListe[i].zipCode;',
'                         break;',
'            case ''str'' : listValue = autocompleteListe[i].street; ',
'                         break;',
'        }',
'',
'        var foundAt = listValue.toUpperCase().indexOf(val.toUpperCase());',
'        var foundLength = val.length;',
'        if (foundAt >= 0) {',
'          divB = document.createElement("DIV");',
'          divB.innerHTML = listValue.substr(0, foundAt) +',
'                        "<strong>" + listValue.substr(foundAt, foundLength) + "</strong>" +',
'                        listValue.substr(foundAt + foundLength) +',
'                        (!!helpValue ? '' ('' + helpValue + '')'': '''')',
'                        ;',
'          ',
'          divB.innerHTML += ''<input type="hidden" value="'' + listValue + ''"'' +',
'                            (!!helpValue ? ''data-helpvalue="'' + helpValue + ''"'' : '''') +',
'                            ''>'';',
'          divB.addEventListener("click", function(e) {',
'              // Wert aus der Liste zuweisen:',
'              var clickedItem = this.getElementsByTagName("input")[0];',
'              input1.value = clickedItem.value;',
'              var helpValue = clickedItem.getAttribute(''data-helpvalue'');',
'              if(!!helpValue) input2.value = helpValue;',
'              closeAllLists();',
'              /// Fokus setzen, wenn die Zuweisung erfolgt ist',
'              if(suchbereich == ''plz'') {',
'                  if(!!input3) input3.focus();',
'              }',
'          });',
'          divA.appendChild(divB);',
'',
'          // Versuch, den Marker wieder herzustellen',
'          if(currentFocus == i) {',
'              divB.classList.add("autocomplete-active"); /// ggf ersetzen durch Aufruf von addActive???',
'          }',
'',
'        }',
'      }    ',
'}',
'',
'',
'',
'function removeActive(x) {',
'    for (var i = 0; i < x.length; i++) {',
'        x[i].classList.remove("autocomplete-active");',
'    }',
'}',
'',
'function addActive(x) {',
'    if (!x) return false;',
'    if(!currentFocus) currentFocus = 0;',
'    removeActive(x);',
'    if (currentFocus >= x.length) {',
unistr('       // wiederholt auf keydown gedr\00FCckt: erneut von oben starten'),
'       currentFocus = 0; ',
'    };',
'    if (currentFocus < 0) currentFocus = (x.length - 1);',
'    try{',
'        x[currentFocus].classList.add("autocomplete-active"); //// @weiter: immer noch Cannot read properties of undefined (reading ''classList'')',
'    } catch(e) {',
'        console.warn(''Fehler bei classList. x='', x, ''currentFocus='', currentFocus)',
'    }',
'}',
'',
'function closeAllLists() {',
'//apex.jQuery(''.autocomplete-items'').remove();',
'    var x = document.getElementsByClassName("autocomplete-items");    ',
'    for (var i = 0; i < x.length; i++) {',
'        //if (elmnt != x[i] && elmnt != input1) {',
'        if(true) {',
'            x[i].parentNode.removeChild(x[i]);',
'        }',
'    }',
'    currentFocus = 0;',
'    suggestlisteOffen = false;',
'}',
''))
,p_plug_display_condition_type=>'VALUE_OF_ITEM_IN_CONDITION_IN_COLON_DELIMITED_LIST'
,p_plug_display_when_condition=>'P100_STEP'
,p_plug_display_when_cond2=>'5:6'
,p_plug_header=>'<script>'
,p_plug_footer=>'</script>'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
,p_plug_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'@ticket FTTH-2810',
'@see https://www.w3schools.com/howto/howto_js_autocomplete.asp'))
);
