wwv_flow_imp_page.create_page_item(
 p_id=>wwv_flow_imp.id(230898305780083718)
,p_name=>'P100_WOHNDAUER'
,p_item_sequence=>30
,p_item_plug_id=>wwv_flow_imp.id(230898218966083717)
,p_prompt=>unistr('l\00E4nger als 6 Monate?')
,p_display_as=>'NATIVE_RADIOGROUP'
,p_named_lov=>'WOHNDAUER (OHNE NO_RESIDENT)'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT CASE r',
'         WHEN ''RESIDENT_LESS_THAN_SIX_MONTHS'' THEN ''nein''',
'         WHEN ''RESIDENT_SIX_OR_MORE_MONTHS''   THEN ''ja''',
'       END AS D',
'     , r',
'  FROM TABLE(PCK_GLASCONTAINER.LOV(''residentStatus''))',
' WHERE r <> ''NO_RESIDENT''',
' ORDER BY',
'       CASE r',
'         WHEN ''RESIDENT_SIX_OR_MORE_MONTHS'' THEN 1     ',
'         WHEN ''RESIDENT_LESS_THAN_SIX_MONTHS''   THEN 2',
'       END'))
,p_grid_label_column_span=>4
,p_field_template=>2318601014859922299
,p_item_template_options=>'#DEFAULT#:t-Form-fieldContainer--large'
,p_lov_display_extra=>'NO'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'number_of_columns', '2',
  'page_action_on_selection', 'NONE')).to_clob
,p_item_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'NO_RESIDENT|RESIDENT_LESS_THAN_SIX_MONTHS|RESIDENT_SIX_OR_MORE_MONTHS',
unistr('Die List of Values hei\00DFt hier "WOHNDAUER (OHNE NO_RESIDENT)", weil die Antwort ja von P100_WOHNT_DORT abh\00E4ngt und im Fall von "nein" der Eintrag "wohnt nicht dort" keinen Sinn erg\00E4be. Der Fragebaum war leider bereits vorgegeben und ist nicht besonder')
||'s stimmig.'))
);
