wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(246642847765433674)
,p_event_id=>wwv_flow_imp.id(230896476813083700)
,p_event_result=>'TRUE'
,p_action_sequence=>30
,p_execute_on_page_init=>'N'
,p_name=>'Auswahl markieren und in Items speichern'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'markerClass = ''t-Button--success'';',
'$button = $(this.triggeringElement);',
'$(''.dublettensuche button.'' + markerClass ).removeClass(markerClass);',
'$button.addClass(markerClass);',
'apex.item(''P100_IS_DUPLICATE'').setValue(''1'');',
'apex.item(''P100_DUPLICATE_ID'').setValue($button.data(''id''));',
'apex.item(''P100_DUPLICATE_SRC'').setValue($button.data(''src''));',
'var kundennummer = $button.data(''knr'');',
'apex.item(''P100_DUPLICATE_KNR'').setValue(kundennummer);'))
,p_da_action_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('Markiert den angeklickten Button gr\00FCn und setzt die Hidden Items, die die Auswahl des Benutzers speichern:'),
'P100_IS_DUPLICATE  => 1 (Flag "Es wurde eine Auswahl getroffen")',
'P100_DUPLICATE_ID  => Entweder die ROW_ID aus Siebel oder die UUID aus dem Preorder-Buffer',
'P100_DUPLICATE_SRC => INP (Erfasste Daten), SIE (Siebel-Datensatz) oder POB (Preorder-Buffer)',
'',
'Kundennummer kann auch leer sein bei SRC=POB => Die Weitergabe von P100_DUPLICATE_KNR an P100_SIEBEL_KUNDENNUMMER erfolgt im PL/SQL-Prozess'))
);
wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(246643144465433677)
,p_event_id=>wwv_flow_imp.id(230896476813083700)
,p_event_result=>'TRUE'
,p_action_sequence=>40
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>':P100_SIEBEL_KUNDENNUMMER := :P100_DUPLICATE_KNR;'
,p_attribute_02=>'P100_IS_DUPLICATE,P100_DUPLICATE_ID,P100_DUPLICATE_SRC,P100_DUPLICATE_KNR'
,p_attribute_03=>'P100_IS_DUPLICATE,P100_DUPLICATE_ID,P100_DUPLICATE_SRC,P100_DUPLICATE_KNR,P100_SIEBEL_KUNDENNUMMER'
,p_attribute_04=>'N'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
,p_da_action_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('Schickt die zuvor aktualisierten Session States der Hidden Items zur Datenbank. Das HTML-Hilfs-Item P100_DUPLICATE_KNR wird an das Gesch\00E4fts-Item P100_SIEBEL_KUNDENNUMMER weitergegeben.'),
'/// Code funktioniert, aber in der Developer-Console erscheint aufgrund der dort genannten "Items to Submit" die Warnung: "No column exists with static ID:  P100_DUPLICATE_ID"'))
);
