wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(243947760179875054)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'SIEBEL Kundendaten holen'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- /////// @todo konsolidieren mit Rendering-Prozess, der auf den Request SIEBEL reagiert (zu viele Formatierungen doppelt kodieren)',
'DECLARE',
'  v_onkz  VARCHAR2(100);',
'  v_nr    VARCHAR2(100);',
'BEGIN',
'PCK_GLASCONTAINER.p_get_siebel_kundendaten',
'  (',
'    piv_kundennummer       => :P100_SIEBEL_KUNDENNUMMER',
'    --',
'   ,pov_message            => :P100_SIEBEL_MESSAGE',
'   ,pov_global_id          => :P100_SIEBEL_GLOBAL_ID',
'   ,pov_vorname            => :P100_SIEBEL_VORNAME',
'   ,pov_nachname           => :P100_SIEBEL_NACHNAME',
'   ,pod_geburtsdatum       => :P100_SIEBEL_GEBURTSDATUM',
'   ,pov_anrede             => :P100_SIEBEL_ANREDE',
'   ,pov_titel              => :P100_SIEBEL_TITEL',
'   ,pov_firmenname         => :P100_SIEBEL_FIRMENNAME',
'   ,pov_strasse            => :P100_SIEBEL_STRASSE_OHNE_HAUSNR',
'   ,pov_hausnr             => :P100_SIEBEL_HAUSNR',
'   ,pov_plz                => :P100_SIEBEL_PLZ',
'   ,pov_ort                => :P100_SIEBEL_ORT',
'   ,pov_ap_email           => :P100_SIEBEL_AP_EMAIL   ',
'   ,pov_ap_mobil_country   => :P100_SIEBEL_AP_MOBIL_VORWAHL',
'   ,pov_ap_mobil_onkz      => v_onkz',
'   ,pov_ap_mobil_nr        => v_nr',
'   ,pov_iban               => :P100_SIEBEL_IBAN',
'  );',
'',
'',
'  :P100_SIEBEL_AP_MOBIL_RUFNUMMER := trim(v_onkz) || '' '' || v_nr;',
'  END;',
'',
unistr('  -- Alte Display-Items bef\00FCllen:'),
'  :P100_SIEBEL_STRASSE := :P100_SIEBEL_STRASSE_OHNE_HAUSNR || '' '' || :P100_SIEBEL_HAUSNR;',
'  :P100_SIEBEL_PLZ_ORT := :P100_SIEBEL_PLZ || '' '' || :P100_SIEBEL_ORT;',
'',
'  -- @ticket FTTH-4084:',
'  IF :P100_SIEBEL_MESSAGE IS NOT NULL THEN',
'    :P100_SIEBEL_KUNDENNUMMER := NULL; -- gibt dem User die Chance, eine neue KNr einzugeben',
'  END IF;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(221125100330263898)
,p_process_when=>'P100_SIEBEL_KUNDENNUMMER'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>50906632182666410
,p_process_comment=>'Reagiert auf den Button "Kundendaten abrufen" oder die Vorbelegung aus SIEBEL.'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(251609161016763561)
,p_process_sequence=>50
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'[2] Anzahl Dubletten ermitteln (Neukunde, ohne Fuzzy)'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT COUNT(*)',
'  INTO :P100_ANZAHL_DUBLETTEN_SIE',
'  FROM  (',
unistr('-- ACHTUNG: Prinzipiell dieselbe folgende Abfrage muss im Interactive Report der Dublettensuche ausgef\00FChrt werden,'),
'-- nachdem der Wizard anhand von P100_ANZAHL_DUBLETTEN entschieden hat, die Dubletten-Seite anzuzeigen.',
'    SELECT 1',
'    FROM TABLE (',
'           --- PCK_FUZZYDOUBLE.ft_vorbestellung_dublettencheck( -- @date 2024-06-18 ersetzt durch:',
'               PCK_GLASCONTAINER_ORDER.ft_vorbestellung_dublettencheck(',
'                  piv_nachname     => :P100_NEUKUNDE_NACHNAME',
'                , piv_vorname      => :P100_NEUKUNDE_VORNAME',
'                , pid_geburtsdatum => TO_DATE(:P100_NEUKUNDE_GEBURTSDATUM)',
'                , piv_firmenname   => :P100_NEUKUNDE_FIRMENNAME',
'                , piv_strasse      => :P100_STRAV_STRASSE',
'                , piv_hausnummer   => TRIM(:P100_STRAV_HAUSNR || '' '' || :P100_STRAV_HAUSNR_ZUSATZ)',
'                , piv_plz          => :P100_STRAV_PLZ',
'                , piv_ort          => :P100_STRAV_ORT',
'                , piv_iban         => :P100_NEUKUNDE_IBAN',
'                , pin_ignore_service_errors => :P10100_IGNORE_FUZZY_SERVICE_ERRORS',
unistr('                , pin_find_1_only  => 0 -- einer gen\00FCgt schon, aber @ticket FTTH-4003: jetzt wollen wir echte Zahlen sehen. war: 1'),
'                , piv_suchbereich  => ''SIE''',
'           )',
'        )',
');',
'',
'SELECT COUNT(*)',
'  INTO :P100_ANZAHL_DUBLETTEN_POB',
'  FROM  (',
unistr('-- ACHTUNG: Prinzipiell dieselbe folgende Abfrage muss im Interactive Report der Dublettensuche ausgef\00FChrt werden,'),
'-- nachdem der Wizard anhand von P100_ANZAHL_DUBLETTEN entschieden hat, die Dubletten-Seite anzuzeigen.',
'    SELECT 1',
'    FROM TABLE (',
'           --- PCK_FUZZYDOUBLE.ft_vorbestellung_dublettencheck( -- @date 2024-06-18 ersetzt durch:',
'               PCK_GLASCONTAINER_ORDER.ft_vorbestellung_dublettencheck(',
'                  piv_nachname     => :P100_NEUKUNDE_NACHNAME',
'                , piv_vorname      => :P100_NEUKUNDE_VORNAME',
'                , pid_geburtsdatum => TO_DATE(:P100_NEUKUNDE_GEBURTSDATUM)',
'                , piv_firmenname   => :P100_NEUKUNDE_FIRMENNAME',
'                , piv_strasse      => :P100_STRAV_STRASSE',
'                , piv_hausnummer   => TRIM(:P100_STRAV_HAUSNR || '' '' || :P100_STRAV_HAUSNR_ZUSATZ)',
'                , piv_plz          => :P100_STRAV_PLZ',
'                , piv_ort          => :P100_STRAV_ORT',
'                , piv_iban         => :P100_NEUKUNDE_IBAN',
'                , pin_ignore_service_errors => :P10100_IGNORE_FUZZY_SERVICE_ERRORS',
unistr('                , pin_find_1_only  => 0 -- einer gen\00FCgt schon, aber @ticket FTTH-4003: jetzt wollen wir echte Zahlen sehen. war: 1'),
'                , piv_suchbereich  => ''POB''',
'           )',
'        )',
');',
'',
':P100_ANZAHL_DUBLETTEN := TO_NUMBER(:P100_ANZAHL_DUBLETTEN_SIE) + TO_NUMBER(:P100_ANZAHL_DUBLETTEN_POB);'))
,p_process_clob_language=>'PLSQL'
