wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(229251569765194604)
,p_process_sequence=>20
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'STRAV und Vermarktungslcuster einlesen'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    SELECT a.str',
'         , a.hnr',
'         , a.hnr_zus',
'         , a.plz',
'         , a.ort',
'         , vco.vc_lfd_nr',
'         , vc.status',
'         , vc.bezeichnung',
'         , vc.mindestbandbreite',
'         , vc.zielbandbreite_geplant',
'         , vc.ausbau_plan_termin',
'         , vc.kosten_hausanschluss',
'         , CASE WHEN vc.kosten_hausanschluss > 0 THEN ''ja'' ELSE ''nein'' END',
'         , vc.kundenauftrag_erforderlich',
'         , COALESCE(:P100_MANDANT, vc.mandant) AS MANDANT -- @ticket FTTH-4084',
'         , PCK_GLASCONTAINER.fv_mandant_display(vc.mandant) -- @ticket FTTH-3495',
'         , CASE WHEN vc.dnsttp_lfd_nr IN (89, 90) -- ''FTTH BSA L2'', ''FTTH BSA L2 DG'' -- @ticket FTTH-4186',
'                                                  -- ///// die anderen nicht???',
'         -- @todo //// Eigene Funktion schreiben',
'           THEN COALESCE(',
'              PCK_GLASCONTAINER.fv_technologie(vc.dnsttp_lfd_nr) -- @ticket FTTH-4186: Reihenfolge im Coalesce umgedreht,',
'                                                                 -- damit die Vermarktungscluster-Technologie (z.B. FTTH BSA L2) immer Vorrang hat',
'             ,PCK_GLASCONTAINER.fv_ausbau_technologie(:P100_HAUS_LFD_NR) -- @ticket FTTH-4077',
'           ) ',
'           ELSE COALESCE(',
unistr('              -- wie zuvor -- @todo kl\00E4ren: Es muss ja einen Grund gegeben haben, die STRAV-Info zu bevorzugen:'),
'              PCK_GLASCONTAINER.fv_ausbau_technologie(:P100_HAUS_LFD_NR) -- @ticket FTTH-4077               ',
'             ,PCK_GLASCONTAINER.fv_technologie(vc.dnsttp_lfd_nr) ',
'           )',
'           END ',
'           AS TECHNOLOGIE',
'         , vc.wholebuy',
'         , CASE WHEN a.onkz IS NOT NULL THEN ''0'' || LTRIM(a.onkz, ''0'') END',
'         , a.adresse_kompl --FTTH-4622',
'      INTO :P100_STRAV_STRASSE',
'         , :P100_STRAV_HAUSNR',
'         , :P100_STRAV_HAUSNR_ZUSATZ',
'         , :P100_STRAV_PLZ',
'         , :P100_STRAV_ORT',
'         , :P100_VC_LFD_NR',
'         , :P100_VC_STATUS',
'         , :P100_VC_BEZEICHNUNG',
'         , :P100_VC_MIN_BANDBREITE',
'         , :P100_VC_MAX_BANDBREITE',
'         , :P100_AUSBAU_PLAN_TERMIN',
'         , :P100_KOSTEN_HAUSANSCHLUSS',
'         , :P100_ANSCHLUSS_KOSTENPFLICHTIG',
'         , :P100_VC_KUNDENAUFTRAG_ERFORDERLICH',
'         , :P100_MANDANT',
'         , :P100_MANDANT_DISPLAY',
'         , :P100_TECHNOLOGIE',
'         , :P100_WHOLEBUY',
'         , :P100_ABW_VORWAHL_HIDDEN',
'         , :P100_STRAV_ADRESSE_KOMPLETT --FTTH-4622',
'      FROM v_adressen a',
'      LEFT JOIN vermarktungscluster_objekt vco ON (a.haus_lfd_nr = vco.haus_lfd_nr)',
'      LEFT JOIN vermarktungscluster vc ON (vc.vc_lfd_nr = vco.vc_lfd_nr AND vc.status IN (''PREMARKETING'', ''UNDERCONSTRUCTION'') )',
'     WHERE a.haus_lfd_nr = :P100_HAUS_LFD_NR',
'    ;',
unistr('    -- 2024-08-27 @FTTH-4084: Ersatzwerte f\00FCr Wholebuy, wenn kein Vermarktungscluster zugeordnet ist:'),
'    IF :P100_VC_MIN_BANDBREITE IS NULL THEN  ',
'        :P100_VC_MIN_BANDBREITE := 50;',
'        :P100_VC_MAX_BANDBREITE := COALESCE(:P100_VC_MAX_BANDBREITE, 1000);',
'    END IF;',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        RAISE_APPLICATION_ERROR(-20999, ''///// Ermittlung des Vermarktungsclusters nicht erfolgreich'');',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P100_VC_LFD_NR IS NULL AND',
':P100_AUSBAU_PLAN_TERMIN IS NULL',
''))
,p_process_when_type=>'EXPRESSION'
,p_process_when2=>'PLSQL'
,p_internal_uid=>25088419137092314
,p_process_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('Bestimmt den Vermarktungscluster und dessen Stammdaten. Wichtig: Die aufrufende Seite (z.B. Adresssuche Seite 14) darf ausschlie\00DFlich die P100_HAUS_LFD_NR setzen und nicht ebenfalls die P100_VC_LFD_NR, da ansonsten dieser Prozess nicht l\00E4uft. @ticket')
||' FTTH-3097: Technologie und Wholebuy werden eingelesen. @ticket FTTH-4077: Vorrangig wird die Ausbautechnologie am Objekt ermittelt, erst wenn diese nicht existiert, diejenige im Vermarktungscluster.',
unistr('@ticket FTTH-4084: Nur anzeigen, wenn kein Plantermin berechnet worden ist (wegen SIEBEL). JOINs ge\00E4ndert zu LEFT JOINs, denn SIEBEL-Objekte bei Wholebuy-Vorbestellung befinden sich nicht unbedingt in Vermarktungsclustern!')))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(205374783768516707)
,p_process_sequence=>30
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Siebel Vorbelegung: Daten einlesen'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P100_SIEBEL_KUNDENNUMMER := :P14_KUNDENNUMMER;',
':P100_MANDANT             := UPPER(:P14_MANDANT);',
':P100_HAUS_LFD_NR         := :P14_HAUS_LFD_NR;',
':P100_KUNDENSTATUS        := ''B''; -- Bestandskunde',
unistr('-- Pr\00FCfen warum der link auf Seite 14 beides nicht \00FCbergibt'),
'',
':P100_TECHNOLOGIE        := :P14_TECHNOLOGIE;',
':P100_WHOLEBUY           := :P14_WHOLEBUY_PARTNER;',
':P100_VC_STATUS          := :P14_AUSBAUSTATUS;',
'',
':P100_AUSBAU_PLAN_TERMIN := PCK_GLASCONTAINER_ORDER.fd_ausbau_plan_termin(piv_wholebuy => :P100_WHOLEBUY);',
'',
':P100_SIEBEL_VORBELEGUNG := ''Kundennummer (''  || :P100_SIEBEL_KUNDENNUMMER || '')''',
'                         || '', Mandant (''     || PCK_GLASCONTAINER.fv_mandant_display(:P100_MANDANT) || '')''',
'                         || '', HAUS_LFD_NR ('' || :P100_HAUS_LFD_NR || '')''',
'                          ;',
'',
':P100_SIEBEL_ERMITTLUNG  := ''Wholebuy-Partner (''  || :P100_WHOLEBUY || '')''',
'                         || '', Technologie (''     || :P100_TECHNOLOGIE || '')''',
'                         || '', Ausbaustatus (''     || :P100_VC_STATUS || '')''',
'                          ;',
'',
'-- Derselbe Code steht im Submit-Prozess -- ////////// @todo konsolidieren',
'DECLARE',
'  v_onkz  VARCHAR2(100);',
'  v_nr    VARCHAR2(100);',
'BEGIN',
'PCK_GLASCONTAINER.p_get_siebel_kundendaten',
'  (',
'    piv_kundennummer       => :P100_SIEBEL_KUNDENNUMMER',
'    --',
'   ,pov_message            => :P100_SIEBEL_MESSAGE',
'   ,pov_global_id          => :P100_SIEBEL_GLOBAL_ID',
'   ,pov_vorname            => :P100_SIEBEL_VORNAME',
'   ,pov_nachname           => :P100_SIEBEL_NACHNAME',
'   ,pod_geburtsdatum       => :P100_SIEBEL_GEBURTSDATUM',
'   ,pov_anrede             => :P100_SIEBEL_ANREDE',
'   ,pov_titel              => :P100_SIEBEL_TITEL',
'   ,pov_firmenname         => :P100_SIEBEL_FIRMENNAME',
'   ,pov_strasse            => :P100_SIEBEL_STRASSE_OHNE_HAUSNR',
'   ,pov_hausnr             => :P100_SIEBEL_HAUSNR',
'   ,pov_plz                => :P100_SIEBEL_PLZ',
'   ,pov_ort                => :P100_SIEBEL_ORT',
'   ,pov_ap_email           => :P100_SIEBEL_AP_EMAIL   ',
'   ,pov_ap_mobil_country   => :P100_SIEBEL_AP_MOBIL_VORWAHL',
'   ,pov_ap_mobil_onkz      => v_onkz',
'   ,pov_ap_mobil_nr        => v_nr',
'   ,pov_iban               => :P100_SIEBEL_IBAN',
'  );',
'',
'',
'',
'  :P100_SIEBEL_AP_MOBIL_RUFNUMMER := trim(v_onkz) || '' '' || v_nr;',
'  END;',
'',
unistr('  -- Alte Display-Items bef\00FCllen:'),
'  :P100_SIEBEL_STRASSE := :P100_SIEBEL_STRASSE_OHNE_HAUSNR || '' '' || :P100_SIEBEL_HAUSNR;',
'  :P100_SIEBEL_PLZ_ORT := :P100_SIEBEL_PLZ || '' '' || :P100_SIEBEL_ORT;',
'',
'  -- @ticket FTTH-4084:',
'  IF :P100_SIEBEL_MESSAGE IS NOT NULL THEN',
'    :P100_SIEBEL_KUNDENNUMMER := NULL; -- gibt dem User die Chance, eine neue KNr einzugeben',
'  END IF;',
'',
'  -- @ticket FTTH-4222:',
'  :P100_KONTEXT := ''SIEBEL'';  '))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'SIEBEL'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>54286003162507626
,p_process_comment=>unistr('@krakar @ticket Ftth-4084: Die von Siebel \00FCbergebene Kundennummer wird aus Seite 14 eingelesen und in den ITEM P100_SIEBEL_KUNDENNUMMER \00FCbergeben')
);
end;
