'        :P100_KUNDENREFERENZ_DAT := ''der Kundin'';',
'        :P100_KUNDENREFERENZ_AKK := ''die Kundin'';',
'    WHEN ''MISTER'' THEN',
'        :P100_KUNDENREFERENZ_NOM := ''der Kunde'';',
'        :P100_KUNDENREFERENZ_GEN := ''des Kunden'';',
'        :P100_KUNDENREFERENZ_DAT := ''dem Kunden'';',
'        :P100_KUNDENREFERENZ_AKK := ''den Kunden'';',
'    ELSE',
'        :P100_KUNDENREFERENZ_NOM := ''der Kunde/die Kundin'';',
'        :P100_KUNDENREFERENZ_GEN := ''der Kundin/des Kunden'';',
'        :P100_KUNDENREFERENZ_DAT := ''der Kundin/dem Kunden'';',
'        :P100_KUNDENREFERENZ_AKK := ''den Kunden/die Kundin'';',
'END CASE;',
'',
'IF :P100_NAME IS NULL THEN :P100_NAME := COALESCE(:P100_NEUKUNDE_NACHNAME, :P100_SIEBEL_NACHNAME); END IF;',
