wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(246643258219433678)
,p_process_sequence=>30
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>unistr('[4] Dublette ist ausgew\00E4hlt')
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P100_IS_DUPLICATE := 1; -- wird bereits in der DA gemacht, aber sicher ist sicher',
'',
'CASE WHEN :P100_DUPLICATE_SRC = ''INP''',
'',
'    THEN -- weiter als Neukunde mit den erfassten Daten:',
unistr('        NULL; -- Dann muss \00FCberhaupt nichts unternommen werden, es geht weiter wie bisher,'),
'              -- lediglich isDuplicate = true wird dem Order-Service mitgeteilt',
'    ',
'    WHEN :P100_DUPLICATE_SRC IN (''SIE'', ''PHO'', ''BNK'') THEN -- weiter mit den Daten aus Siebel als Bestandskunde',
'        :P100_DUPLICATE_SRC := ''SIE''; -- normalisieren, die Info PHO oder BNK brauchen wir ab hier nicht mehr',
unistr('        :P100_SIEBEL_GLOBAL_ID := :P100_DUPLICATE_ID; -- damit beim R\00FCcksprung erfolgreich validiert werden kann'),
'        :P100_KUNDENSTATUS := ''B'';',
'        PCK_GLASCONTAINER_ORDER.FV_SIEBEL_KUNDENDATEN_UEBERNEHMEN(',
'             piv_global_id           => :P100_DUPLICATE_ID',
'           , piv_kundennummer        => :P100_SIEBEL_KUNDENNUMMER -- :P100_SIEBEL_KUNDENNUMMER wurde bereits in der Dynamic Action gesetzt',
'           , pov_anrede              => :P100_SIEBEL_ANREDE',
'           , pov_titel               => :P100_SIEBEL_TITEL ',
'           , pov_vorname             => :P100_SIEBEL_VORNAME ',
'           , pov_nachname            => :P100_SIEBEL_NACHNAME',
'           , pod_geburtsdatum        => :P100_SIEBEL_GEBURTSDATUM',
'           , pov_firmenname          => :P100_SIEBEL_FIRMENNAME',
'           , pov_ap_email            => :P100_SIEBEL_AP_EMAIL',
'           , pov_ap_mobil_vorwahl    => :P100_SIEBEL_AP_MOBIL_VORWAHL',
'           , pov_ap_mobil_rufnummer  => :P100_SIEBEL_AP_MOBIL_RUFNUMMER',
'           , pov_iban                => :P100_SIEBEL_IBAN       ',
'        );      ',
'        -- @weiter 2024-06-11: ////// Exceptions zu einem nachvollziehbaren Abbruch bringen',
'        ',
'    WHEN :P100_DUPLICATE_SRC IN (''POB'') THEN -- weiter mit den Daten aus dem Preorder-Buffer (entweder Neu- oder Bestandskunde)    ',
'        IF :P100_SIEBEL_KUNDENNUMMER IS NULL THEN -- Neukunde',
'            :P100_KUNDENSTATUS := ''N'';',
'           BEGIN',
'                SELECT CUSTOMER_SALUTATION',
'                     , CUSTOMER_TITLE',
'                     , CUSTOMER_NAME_FIRST',
'                     , CUSTOMER_NAME_LAST',
'                     , CUSTOMER_BIRTHDATE',
'                     , CUSTOMER_BUSINESSNAME',
'                     , CUSTOMER_EMAIL',
'                     , CUSTOMER_PHONE_COUNTRYCODE',
'                     , CUSTOMER_PHONE_AREACODE || CUSTOMER_PHONE_NUMBER',
'                     , ACCOUNT_IBAN',
'                  INTO :P100_NEUKUNDE_ANREDE',
'                     , :P100_NEUKUNDE_TITEL ',
'                     , :P100_NEUKUNDE_VORNAME ',
'                     , :P100_NEUKUNDE_NACHNAME',
'                     , :P100_NEUKUNDE_GEBURTSDATUM',
'                     , :P100_NEUKUNDE_FIRMENNAME',
'                     , :P100_NEUKUNDE_EMAIL',
'                     , :P100_NEUKUNDE_VORWAHL',
'                     , :P100_NEUKUNDE_RUFNUMMER',
'                     , :P100_NEUKUNDE_IBAN      ',
'                  FROM FTTH_WS_SYNC_PREORDERS',
'                 WHERE ID = :P100_DUPLICATE_ID',
'                   AND (:P100_SIEBEL_KUNDENNUMMER IS NULL OR CUSTOMERNUMBER = :P100_SIEBEL_KUNDENNUMMER);',
'                :P100_NEUKUNDE_EMAIL_VERGLEICH := :P100_NEUKUNDE_EMAIL;',
'            EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'                RAISE_APPLICATION_ERROR(-20999, ''POB-Neukundendaten konnten nicht abgerufen werden'');',
'            WHEN TOO_MANY_ROWS THEN',
'                RAISE_APPLICATION_ERROR(-20999, ''POB-Neukundendaten konnten nicht eindeutig zugeordnet werden'');',
'            END;            ',
'        ELSE -- Bestandskunde',
'            :P100_KUNDENSTATUS := ''B'';',
'         -- :P100_SIEBEL_KUNDENNUMMER wurde bereits in der Dynamic Action gesetzt',
unistr('            :P100_SIEBEL_GLOBAL_ID := :P100_DUPLICATE_ID; -- damit beim R\00FCcksprung erfolgreich validiert werden kann'),
'           BEGIN',
'                SELECT CUSTOMER_SALUTATION',
'                     , CUSTOMER_TITLE',
'                     , CUSTOMER_NAME_FIRST',
'                     , CUSTOMER_NAME_LAST',
'                     , CUSTOMER_BIRTHDATE',
'                     , CUSTOMER_BUSINESSNAME',
'                     , CUSTOMER_EMAIL',
'                     , CUSTOMER_PHONE_COUNTRYCODE',
'                     , CUSTOMER_PHONE_AREACODE || CUSTOMER_PHONE_NUMBER',
'                     , ACCOUNT_IBAN',
'                  INTO :P100_SIEBEL_ANREDE',
'                     , :P100_SIEBEL_TITEL ',
'                     , :P100_SIEBEL_VORNAME ',
'                     , :P100_SIEBEL_NACHNAME',
'                     , :P100_SIEBEL_GEBURTSDATUM',
'                     , :P100_SIEBEL_FIRMENNAME',
'                     , :P100_SIEBEL_AP_EMAIL',
'                     , :P100_SIEBEL_AP_MOBIL_VORWAHL',
'                     , :P100_SIEBEL_AP_MOBIL_RUFNUMMER',
'                     , :P100_SIEBEL_IBAN      ',
'                  FROM FTTH_WS_SYNC_PREORDERS',
'                 WHERE ID = :P100_DUPLICATE_ID',
'                   AND (:P100_SIEBEL_KUNDENNUMMER IS NULL OR CUSTOMERNUMBER = :P100_SIEBEL_KUNDENNUMMER);',
'            EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'                RAISE_APPLICATION_ERROR(-20999, ''POB-Bestandskundendaten konnten nicht abgerufen werden'');',
'            WHEN TOO_MANY_ROWS THEN',
'                RAISE_APPLICATION_ERROR(-20999, ''POB-Bestandskundendaten konnten nicht eindeutig zugeordnet werden'');',
'            END;',
'        END IF;',
'END CASE;',
''))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>unistr('Dieser Kunde kann nicht f\00FCr die Bestellung verwendet werden. Bitte pflegen Sie die folgenden Daten in Siebel nach. F\00FChren Sie anschlie\00DFend die Bestellung erneut durch: <br/><strong>#SQLERRM_TEXT#</strong>')
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(220876326009136205)
,p_internal_uid=>53602130222225034
,p_process_comment=>'":P100_SIEBEL_KUNDENNUMMER := :P100_DUPLICATE_KNR" muss bereits in der Dynamic Action erfolgt sein'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(232705914968350607)
