'            ,pov_firmenname                     => :P901_CUSTOMER_BUSINESSNAME',
'            ,pov_anrede                         => :P901_CUSTOMER_SALUTATION',
'            ,pov_titel                          => :P901_CUSTOMER_TITLE',
'            ,pov_vorname                        => :P901_CUSTOMER_NAME_FIRST',
'            ,pov_nachname                       => :P901_CUSTOMER_NAME_LAST',
'            ,pod_geburtsdatum                   => :P901_CUSTOMER_BIRTHDATE',
'            ,pov_email                          => :P901_CUSTOMER_EMAIL',
