'            ,pov_laendervorwahl                 => :P901_CUSTOMER_PHONE_COUNTRYCODE',
'            ,pov_vorwahl                        => :P901_CUSTOMER_PHONE_AREACODE',
'            ,pov_telefon                        => :P901_CUSTOMER_PHONE_NUMBER',
'         -- ,pov_passwort                       => :P901_CUSTOMER_PASSWORD -- entfernt 2025-01-21',
'        --                                        ',
'            ,pov_providerwechsel                => :P901_PROVIDERWECHSEL',
'            ,pov_providerw_aktueller_anbieter   => :P901_PROVIDERCHG_CURRENT_PROVIDER',
'            ,pov_providerw_anschluss_gekuendigt => :P901_PROVIDERCHG_CONTRACT_CANCELLED',
