wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(201916496970045910)
,p_plug_name=>unistr('Wann wurden die Jobs ausgef\00FChrt?')
,p_parent_plug_id=>wwv_flow_imp.id(82049780291968937)
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>20
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH FTTH_FACTORY_JOBS AS (',
'  SELECT ''JOB_GLASCONTAINER_REFRESH_MV'' AS JOB_NAME FROM DUAL UNION ALL',
'  SELECT ''JOB_VERMARKTCLUSTER_STAT'' FROM DUAL UNION ALL',
'  SELECT ''JOB_SIEBELREADY_VCO_DEL'' FROM DUAL UNION ALL',
'--SELECT ''JOB_VMC_WHOLEBUY_POB'' FROM DUAL UNION ALL -- deaktiviert 2025-03',
'  SELECT ''JOB_GLASCONTAINER'' FROM DUAL -- @ticket FTTH-5062',
'),',
'KALENDER AS (',
'    SELECT TRUNC(SYSDATE) + 1 - LEVEL AS DATUM',
'      FROM DUAL',
'    CONNECT BY LEVEL <= 365',
')',
'SELECT KALENDER.DATUM',
'     , jrd.log_id',
'     , trunc(jrd.log_date) as log_date',
'     , FTTH_FACTORY_JOBS.JOB_NAME AS job_name',
'     , jrd.status',
'     , jrd.req_start_date',
'     , jrd.actual_start_date',
'     , substr(jrd.run_duration, instr(jrd.run_duration, '':'')-2, 8) as run_duration',
'       -- 00:00:02 = 2 Sekunden',
'     , to_number(substr(jrd.run_duration, instr(jrd.run_duration, '':'')-2, 2)) * 60 * 60',
'      +to_number(substr(jrd.run_duration, instr(jrd.run_duration, '':'')+1, 2)) * 60',
'      +to_number(substr(jrd.run_duration, instr(jrd.run_duration, '':'')+4, 2))',
'       AS run_duration_seconds',
'     , jrd.instance_id',
'     , jrd.additional_info',
'     , jrd.error#      ',
'     , jrd.errors',
'     , j.job_style',
'     , j.job_creator',
'     , j.program_name',
'     , j.job_type',
'     , j.job_action',
'     , j.schedule_type',
'     , j.schedule_name',
'     , j.repeat_interval',
'     , j.enabled',
'     , j.state',
'     , j.job_priority',
'     , j.run_count',
'     , j.failure_count',
'     , j.last_start_date',
'     , j.next_run_date',
'     , j.comments',
'  FROM KALENDER',
'  CROSS JOIN FTTH_FACTORY_JOBS',
'  LEFT JOIN user_scheduler_job_run_details jrd ON (jrd.job_name = FTTH_FACTORY_JOBS.job_name AND TRUNC(jrd.log_date) = KALENDER.DATUM)',
'  LEFT JOIN user_scheduler_jobs j ON j.job_name = FTTH_FACTORY_JOBS.job_name'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>'Datenbank-Jobs'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
