wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(262867687021823713)
,p_plug_name=>unistr('Synchronisierungsvorg\00E4nge')
,p_region_template_options=>'#DEFAULT#:t-Region--noPadding:js-useLocalStorage:is-collapsed:t-Region--accent15:t-Region--noBorder:t-Region--scrollBody'
,p_plug_template=>2664334895415463485
,p_plug_display_sequence=>50
,p_include_in_reg_disp_sel_yn=>'Y'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT rest_source_name,',
'       status,',
'       status_code,',
'       start_timestamp,',
'       end_timestamp,',
'       runtime,',
'       substr(to_char(runtime), 15, 5) AS dauer,',
'       EXTRACT(HOUR FROM runtime)   AS runtime_hours,',
'       EXTRACT(MINUTE FROM runtime) AS runtime_minutes,',
'       EXTRACT(SECOND FROM runtime) AS runtime_seconds,',
'       rows_processed,',
'       sync_messages,',
'       is_job',
'  FROM (',
'    SELECT rest_source_name,',
'           status,',
'           status_code,',
'           start_timestamp,',
'           end_timestamp,',
'           end_timestamp - start_timestamp AS runtime,',
'           rows_processed,',
'           sync_messages,',
'           is_job',
'      FROM apex_rest_source_sync_log',
'     WHERE application_id = :APP_ID',
'     -- AND rest_source_name IN (''preorders (Auftragsliste)''',
')'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_required_role=>wwv_flow_imp.id(238128121341675592)
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
,p_prn_height=>8.5
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>unistr('Synchronisierungsvorg\00E4nge')
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
