,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'htp.p(''<ol>'');',
'FOR todo IN (SELECT D AS TEXT, R AS PRIO FROM TABLE(PCK_GLASCONTAINER.TODOLIST)) LOOP',
'  IF todo.TEXT IS NULL THEN',
'    htp.p(''<hr style="margin-top: 1em;" />'');',
'  ELSE',
'    htp.p(''<li>'' || todo.TEXT || ''</li>'');',
'  END IF;',
'END LOOP;',
'htp.p(''</ol>'');',
'EXCEPTION',
'  WHEN OTHERS THEN',
'    htp.p(''Liste kann nicht angezeigt werden: '' || SQLERRM);',
'END;'))
,p_plug_source_type=>'NATIVE_PLSQL'
,p_plug_required_role=>wwv_flow_imp.id(216442017267608171)
