wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(321594252599057725)
,p_plug_name=>'Fehler-Logs'
,p_region_css_classes=>'infobox'
,p_region_template_options=>'#DEFAULT#:t-ContentBlock--padded:t-ContentBlock--h3:t-ContentBlock--lightBG'
,p_plug_template=>2322115667525957943
,p_plug_display_sequence=>100
,p_plug_new_grid_row=>false
,p_plug_grid_column_span=>4
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<pre class="copyToClipboard" style="margin:0">SELECT log_id',
'     , to_char(inserted, ''YYYY-MM-DD HH24:MI:SS'') AS ZEIT',
'     , scope, user_name, module, action, routine_name',
'     , line, error_code, error_message, message ',
'  FROM CORE.LOGS',
' WHERE (scope = ''POB'' OR module LIKE ''ROMA_MAIN/APEX:APP 2022%'')',
' ORDER BY log_id DESC;',
'</pre>'))
,p_plug_required_role=>wwv_flow_imp.id(238128469706691677)
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(335125770169263707)
,p_plug_name=>'Konzepte, Anwendungs-Architektur und Dokumentation ...'
,p_region_template_options=>'#DEFAULT#:js-useLocalStorage:is-collapsed:t-Region--noBorder:t-Region--scrollBody:margin-top-none:margin-bottom-none'
,p_plug_template=>2664334895415463485
,p_plug_display_sequence=>10
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_grid_column_span=>9
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('<p>Die APEX-Applikation "Glascontainer" erlaubt den Mitarbeiter*innen, die Auftr\00E4ge im FTTH-PreOrder-Buffer einzusehen und, berechtigungsgesteuert, bestimmte Daten zu \00E4ndern.</p>'),
'',
unistr('<p>Die Bewegungsdaten befinden sich in den Tabellen FTTH_WS_SYNC_PREORDERS und FTTH_WS_SYNC_STORNOGRUENDE (beide sind in den Shared Components mit der entsprechenden REST Data Source verkn\00FCpft und werden automatisch n\00E4chtlich synchronisiert).'),
unistr('Au\00DFerdem erfolgt die Klassifizierung von m\00F6glichen Dubletten in der Zieltabelle FTTH_DUBLETTEN_BEWERTUNG.</p>'),
'<ul>Weitere verwendete Tabellen und Views:',
'<li>APEX_REST_SOURCE_SYNC_LOG</li>    ',
'<li>FTTH_DUBLETTEN_BEWERTUNG</li>',
'<li>FTTH_GLASCONTAINER_AKTIONEN</li>',
'<li>FTTH_GLASCONTAINER_PRODUKTE</li>',
'<li>FTTH_LOG_SIEBEL_READY_VCO</li>',
'<li>FTTH_WEBSERVICE_AUFRUFE</li>',
'<li>POB_ADRESSEN</li>',
'<li>POB_TRACKING, POB_TRACKING_EXTRA</li>',
'<li>V_ADRESSEN</li>',
'',
'</ul>',
'',
unistr('<p><strong>Tickets in JIRA werden im PL/SQL-Quellcode der Packages, in Table- und View-Comments sowie in APEX-Objektkommentaren gem\00E4\00DF der @Tag-Schreibweise erw\00E4hnt und verkn\00FCpft:</strong></p>'),
'<p>Beispielsweise bezieht sich die Quellcode-Fundstelle <tt>@ticket FTTH-1874</tt> auf das JIRA-Ticket <a href="https://jira.netcologne.intern/browse/FTTH-1874">https://jira.netcologne.intern/browse/FTTH-1874</a>, so dass man bei der Suche nach Ticke'
||unistr('t-L\00F6sungen dieses Suchmuster verwenden sollte (APEX-Volltextsuche, USER_SOURCE, USER_VIEWS, USER_TAB_COMMENTS, USER_COL_COMMENTS usw.) Zur strukturierten Suche in den APEX-Objektkommentaren wird in den Entwicklungs- und Testumgebungen der Link zur Se')
||unistr('ite "Entwicklerdokumentation" eingeblendet (siehe Navigationsleiste, rechts oben). Dort erscheinen s\00E4mtliche Entwicklerkommentare, kontextsensitiv f\00FCr die jeweils aktuelle APEX-Seite, in einem Interactive Report.</p>'),
'<p>Die Unit-Test-Suite wird in den Entwicklungsumgebungen (NMCE bzw. NMCE3) hierdurch gestartet:<br/>',
'<tt>SELECT * FROM ROMA_MAIN.UT.RUN(''UT_GLASCONTAINER'');</tt>',
'</p>'))
,p_plug_required_role=>wwv_flow_imp.id(238128121341675592)
,p_required_patch=>wwv_flow_imp.id(228976553402207959)
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
