wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(72458249296963909)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>unistr('Fehler-Logs Fortschritt pr\00FCfen')
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_execution apex_background_process.t_execution;',
'BEGIN',
'    l_execution := apex_background_process.get_execution(',
'                   p_application_id     => 2022,',
'                   p_execution_id       => :P10050_BG_ID_COLLECTION',
'    );',
'    :P10050_BG_STATE_COLLECTION     := l_execution.state ;',
'    :P10050_BG_SOFAR_COLLECTION     := l_execution.sofar ;',
'    :P10050_BG_TOTALWORK_COLLECTION := l_execution.totalwork ;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(72458608082963913)
,p_process_when=>'P10050_BG_ID_COLLECTION'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_process_success_message=>'Die Fehler-Logs sind in Arbeit ... bitte noch etwas Geduld'
,p_internal_uid=>22084656355751404
,p_process_comment=>unistr('Fragt den Fortschritt des Hintergrund-Prozesses ab, der die Fehlerlogs erstellt. Die Schaltfl\00E4che BTN_FEHLERSTATISTIK_3 wird erst eingeblendet, sobald die Fehlerstatistik erfolgreich erstellt wurde.')
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(211170107378286736)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Versionen abfragen'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  FUNCTION ORA(text IN VARCHAR2) return varchar2 is',
'  BEGIN',
'    RETURN ''<span class="u-danger">'' || text || ''</span>'';',
'  END ORA;',
'BEGIN',
'<<APPLICATION>>',
'BEGIN',
'  SELECT :APP_SESSION, application_id, version, workspace_display_name, owner, to_char(last_updated_on, ''YYYY-MM-DD HH24:MI:SS''), last_updated_by',
'    INTO :P10050_APP_SESSION, :P10050_APP_ID, :P10050_APP_VERSION, :P10050_WORKSPACE, :P10050_PARSING_SCHEMA, :P10050_LAST_UPDATED_ON, :P10050_LAST_UPDATED_BY',
'  FROM apex_applications WHERE application_id = :APP_ID;',
'EXCEPTION',
'  WHEN OTHERS THEN',
'    :P10050_APP_ID          := :APP_ID;',
'    :P10050_APP_VERSION     := ''#APP_VERSION#'';',
'    :P10050_WORKSPACE       := ORA(SQLERRM);',
'    :P10050_PARSING_SCHEMA  := NULL;',
'    :P10050_LAST_UPDATED_ON := NULL;',
'    :P10050_LAST_UPDATED_BY := NULL;',
'    ',
'END APPLICATION;',
'',
'<<APPLICATION_COMMENT>>',
'BEGIN',
'  SELECT application_comment',
'    INTO :P10050_APPLICATION_COMMENT',
'    FROM apex_applications',
'   WHERE application_id = :APP_ID;',
'END;',
'',
'<<APEX_VERSION>>',
'BEGIN',
'  SELECT version_no INTO :P10050_APEX_VERSION_NO ',
'   FROM apex_release;',
'EXCEPTION',
'  WHEN OTHERS THEN',
'    :P10050_APEX_VERSION_NO := ORA(SQLERRM);',
'END APEX_VERSION;',
'',
'<<APPLICATION_COMMENT>>',
'BEGIN',
'  SELECT application_comment',
'    INTO :P10050_APPLICATION_COMMENT',
'    FROM apex_applications',
'   WHERE application_id = :APP_ID;',
'END;',
'',
'<<DATABASE>>',
'BEGIN',
'  SELECT global_name || '' (&quot;'' || pck_env.fv_db_name || ''&quot;)'' INTO :P10050_ENVIRONMENT from GLOBAL_NAME;',
'  SELECT banner INTO :P10050_DATABASE_RELEASE FROM v$version WHERE ROWNUM = 1;',
'  :P10050_APP_URL := APEX_UTIL.HOST_URL || SUBSTR(APEX_PAGE.GET_URL, 1, INSTR(APEX_PAGE.GET_URL, ''/'', -1));',
'EXCEPTION',
'WHEN OTHERS THEN',
'  :P10050_ENVIRONMENT      := ORA(SQLERRM);',
'  :P10050_DATABASE_RELEASE := ORA(SQLERRM);',
'END DATABASE;',
'',
'<<PACKAGES>>',
':P10050_PCK_GLASCONTAINER       := GREATEST(PCK_GLASCONTAINER.version, PCK_GLASCONTAINER.get_body_version);',
':P10050_PCK_GLASCONTAINER_EXT   := GREATEST(PCK_GLASCONTAINER_EXT.version, PCK_GLASCONTAINER_EXT.get_body_version);',
':P10050_PCK_FUZZYDOUBLE         := GREATEST(PCK_FUZZYDOUBLE.version, PCK_FUZZYDOUBLE.get_body_version);',
':P10050_PCK_GLASCONTAINER_DUBL  := GREATEST(PCK_GLASCONTAINER_DUBLETTEN.version, PCK_GLASCONTAINER_DUBLETTEN.get_body_version);',
':P10050_PCK_GLASCONTAINER_ORDER := GREATEST(PCK_GLASCONTAINER_ORDER.version, PCK_GLASCONTAINER_ORDER.get_body_version);',
':P10050_PCK_POB_REST            := GREATEST(PCK_POB_REST.version, PCK_POB_REST.get_body_version);',
':P10050_PCK_VERMARKTUNGSCLUSTER := GREATEST(PCK_VERMARKTUNGSCLUSTER.version, PCK_VERMARKTUNGSCLUSTER.get_body_version);',
':P10050_PCK_GLASCONTAINER_JOBS  := GREATEST(PCK_GLASCONTAINER_JOBS.version, PCK_GLASCONTAINER_JOBS.get_body_version);',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>7006956750184446
,p_process_comment=>unistr('Ermittelt die aktuellen Versionen bestimmter Objekte (haupts\00E4chlich Packages), um sie informativ anzuzeigen')
);
