,p_chart_id=>wwv_flow_imp.id(329415416972718506)
,p_seq=>10
,p_name=>'Fehler-Logs'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH kalender AS (',
'  SELECT trunc(sysdate) + 1 - level AS datum',
'    FROM dual',
'  CONNECT BY',
'    level <= 28',
'), fehlerlogs AS (',
'  SELECT DATUM,',
'         COUNT(*) AS ANZAHL',
'    FROM (',
'    SELECT TRUNC(D001) AS DATUM',
'      FROM APEX_COLLECTIONS C',
'     WHERE COLLECTION_NAME = ''FEHLERSTATISTIK''',
'  )',
'   GROUP BY DATUM',
')',
'SELECT TO_CHAR(kalender.DATUM, ''DD.'') AS LABEL,',
'       fehlerlogs.anzahl             AS value',
'  FROM kalender',
'  LEFT JOIN fehlerlogs',
'ON ( kalender.datum = fehlerlogs.datum )',
' ORDER BY kalender.datum'))
,p_max_row_count=>90
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
,p_items_label_display_as=>'PERCENT'
,p_threshold_display=>'onIndicator'
);
