wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(56538765106052153)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>unistr('Leeres Datum mit SYDATE f\00FCllen')
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'IF :P10056_DATUM_VON IS NULL THEN ',
'   :P10056_DATUM_VON := TRUNC(TO_DATE(GREATEST(COALESCE(TO_DATE(:P10056_DATUM_BIS), SYSDATE), DATE ''2024-09-20'')));',
'END IF;',
'',
'IF :P10056_DATUM_BIS IS NULL THEN ',
'   :P10056_DATUM_BIS := TRUNC(TO_DATE(GREATEST(COALESCE(TO_DATE(:P10056_DATUM_VON), SYSDATE), TRUNC(SYSDATE))));',
'END IF;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(56537992745052145)
,p_process_when=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P10056_DATUM_VON IS NULL OR',
':P10056_DATUM_BIS IS NULL'))
,p_process_when_type=>'EXPRESSION'
,p_process_when2=>'PLSQL'
,p_process_success_message=>'Datumseingabe wurde korrigiert.'
,p_internal_uid=>6165172164839648
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(56538649646052152)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Datumsbereich korrigieren'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_swap DATE;  ',
'BEGIN',
'  v_swap := TO_DATE(:P10056_DATUM_BIS);',
'  :P10056_DATUM_BIS := :P10056_DATUM_VON;',
'  :P10056_DATUM_VON := v_swap;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(56537992745052145)
,p_process_when=>'TO_DATE(:P10056_DATUM_VON) > TO_DATE(:P10056_DATUM_BIS)'
,p_process_when_type=>'EXPRESSION'
,p_process_when2=>'PLSQL'
,p_process_success_message=>'Zeitfenster (von ... bis) wurde korrigiert'
,p_internal_uid=>6165056704839647
,p_process_comment=>'Wenn VON > BIS, drehen wir die Datumsfelder um'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(56538499442052151)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Mindestdatum 2024-09-20'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P10056_DATUM_VON := TO_DATE(GREATEST(DATE ''2024-10-31'', NVL(:P10056_DATUM_VON, TRUNC(SYSDATE))));',
':P10056_DATUM_BIS := TO_DATE(:P10056_DATUM_VON);'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'NVL(TO_DATE(:P10056_DATUM_VON), SYSDATE) < DATE ''2024-10-31'''
,p_process_when_type=>'EXPRESSION'
,p_process_when2=>'PLSQL'
,p_process_success_message=>'Nutzungsdaten werden seit dem 31. Oktober 2024 erhoben.'
,p_internal_uid=>6164906500839646
,p_process_comment=>'Das Datum, an dem das Tracking in der Produktion begonnen hat, ist der 20. Septempber 2024, damals allerdings noch mit einem einfacheren Datenmodell. Seit dem 31.10. wird in der Produktion auch dann getrackt, wenn es nicht zu einem Abschluss kommt. D'
||unistr('as Startdatum f\00FCr die Auswertungen darf nicht vor dem 31.01.2024 liegen, weil sonst keine konsistenten Ergebnisse herauskommen.')
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(74688130114597921)
,p_process_sequence=>10
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>unistr('G\00FCltigkeit Datumseingabe pr\00FCfen')
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P10056_DATUM_VON := TO_DATE(:P10056_DATUM_VON DEFAULT NULL ON CONVERSION ERROR);',
':P10056_DATUM_BIS := TO_DATE(:P10056_DATUM_BIS DEFAULT NULL ON CONVERSION ERROR);'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>24314537173385416
,p_process_comment=>unistr('Stellt sicher, dass die Benutzereingabe nicht zu Fehlermeldungen f\00FChrt, wenn es sich nicht um ein g\00FCltiges Datum handelt. In diesem Fall wird NULL eingesetzt (im Nachfolgeprozess wird NULL mit SYSDATE ersetzt)')
);
