,p_process_sequence=>50
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Zeitraum Quartal'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
':P10056_DATUM_VON := TRUNC(SYSDATE, ''Q'');',
'-- nicht auf das Quartalsende einstellen, weil dies fast niemals der aktuelle Tag ist:',
'-- :P10056_DATUM_BIS := LAST_DAY(ADD_MONTHS(TRUNC(SYSDATE, ''Q''),2));',
'-- sondern: heute',
':P10056_DATUM_BIS := TRUNC(SYSDATE);'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(74687361353597913)
,p_internal_uid=>24313967702385410
,p_process_comment=>'Stellt das Startdatum auf den Beginn des aktuellen Quartals ein (Endedatum ist immer "heute")'
);
end;
