wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(290686279197424820)
,p_plug_name=>unistr('Einstellung f\00FCr n\00E4chtliche Fuzzy-Aktualisierung')
,p_region_name=>'fuzzyJobsEinstellungen'
,p_parent_plug_id=>wwv_flow_imp.id(259423185875197932)
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>50
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT job_name',
'     , enabled',
'     , state',
'     , CASE state WHEN ''SCHEDULED'' THEN ''aktiviert'' WHEN ''DISABLED'' THEN ''ruht'' END AS ZEITPLAN',
'     , last_start_date',
'     , next_run_date',
'     , CASE WHEN next_run_date > SYSDATE AND state = ''SCHEDULED'' THEN next_run_date END as naechster_start',
'     , comments',
'     , ''<button type="button" class="fuzzy-scheduler ''',
'     || CASE job_name WHEN ''JOB_FUZZY_TAEGLICH'' THEN ''taeglich ''',
'                      WHEN ''JOB_FUZZY_WOECHENTLICH'' THEN ''woechentlich ''',
'        END',
'     || CASE state WHEN ''SCHEDULED'' THEN ''job-enabled'' WHEN ''DISABLED'' THEN ''job-disabled'' END',
'     || ''">'' ',
'     || CASE state WHEN ''SCHEDULED'' THEN ''ruhen&nbsp;lassen'' WHEN ''DISABLED'' THEN ''aktivieren'' END || ''</button>'' as aktion',
'  FROM user_scheduler_Jobs',
' WHERE program_name LIKE (''PROGRAM_FUZZY%'')'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>unistr('Einstellung f\00FCr n\00E4chtliche Fuzzy-Aktualisierung')
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
