wwv_flow_imp_page.create_page_item(
 p_id=>wwv_flow_imp.id(238355645939775652)
,p_name=>'P10100_LASTMODIFIEDWITHINDAYS'
,p_item_sequence=>10
,p_item_plug_id=>wwv_flow_imp.id(248936859915564670)
,p_prompt=>unistr('\00C4nderungs-Zeitfenster')
,p_post_element_text=>'&nbsp; Tage'
,p_display_as=>'NATIVE_NUMBER_FIELD'
,p_cSize=>1
,p_grid_label_column_span=>7
,p_field_template=>2318601014859922299
,p_item_template_options=>'#DEFAULT#'
,p_help_text=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('<p>Gibt an, welchen Wert der Parameter lastModifiedWithinDays haben soll, wenn die Synchronisation des Webservices "preorders" manuell oder n\00E4chtlich aufgerufen wird. Dieser Parameter bestimmt, welches Zeitfenster f\00FCr die \00C4nderungen ber\00FCcksichtigt we')
||unistr('rden soll, um die zu \00FCbertragenden Datenmengen und die daf\00FCr ben\00F6tigte Zeit zu begrenzen (anstatt stets alle S\00E4tze zu synchronisieren, selbst wenn keine \00C4nderungen stattgefunden haben).</p>'),
unistr('<p>Beispielsweise werden bei einem Wert von 7 nur diejenigen \00C4nderungen synchronisiert, die innerhalb der letzten 7 Tage stattgefunden haben. Ein Wert von 0 bedeutet: "Nur \00C4nderungen von heute".</p>'),
unistr('<p>Wird der Wert leer gelassen, dann werden s\00E4mtliche Datens\00E4tze im PreOrder-Buffer synchronisiert.</p>')))
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'min_value', '0',
  'number_alignment', 'right',
  'virtual_keyboard', 'text')).to_clob
);
wwv_flow_imp_page.create_page_item(
 p_id=>wwv_flow_imp.id(238356489301775654)
,p_name=>'P10100_MIN_SYNC_INTERVAL_PREORDERS'
