'autocomplete(''ort'', document.getElementById("P99100_ORT"), document.getElementById("P99100_PLZ"));',
'autocomplete(''str'', document.getElementById("P99100_STRASSE"), document.getElementById("P99100_PLZ"));'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'.autocomplete {',
'  /*the container must be positioned relative:*/',
